const API_BASE_URL = 'http://localhost:8000/api'; // Ajustez l'URL de votre serveur Laravel

const getHeaders = () => ({
  'Content-Type': 'application/json',
  'Accept': 'application/json',
  // 'Authorization': `Bearer ${localStorage.getItem('token')}` // Décommenter si vous utilisez Sanctum
});

export const apiService = {
  // Drugs
  getDrugs: async () => {
    const res = await fetch(`${API_BASE_URL}/drugs`, { headers: getHeaders() });
    return res.json();
  },
  saveDrug: async (drug: any) => {
    const method = drug.id && !drug.id.toString().startsWith('temp_') ? 'PUT' : 'POST';
    const url = method === 'PUT' ? `${API_BASE_URL}/drugs/${drug.id}` : `${API_BASE_URL}/drugs`;
    const res = await fetch(url, {
      method,
      headers: getHeaders(),
      body: JSON.stringify(drug)
    });
    return res.json();
  },
  deleteDrug: async (id: string) => {
    await fetch(`${API_BASE_URL}/drugs/${id}`, { method: 'DELETE', headers: getHeaders() });
  },

  // Sales
  getSales: async () => {
    const res = await fetch(`${API_BASE_URL}/sales`, { headers: getHeaders() });
    return res.json();
  },
  createSale: async (sale: any) => {
    const res = await fetch(`${API_BASE_URL}/sales`, {
      method: 'POST',
      headers: getHeaders(),
      body: JSON.stringify(sale)
    });
    return res.json();
  },

  // Auth
  login: async (credentials: any) => {
    const res = await fetch(`${API_BASE_URL}/login`, {
      method: 'POST',
      headers: getHeaders(),
      body: JSON.stringify(credentials)
    });
    if (!res.ok) throw new Error('Identifiants invalides');
    return res.json();
  },

  // Suppliers & Insurances
  getSuppliers: async () => {
    const res = await fetch(`${API_BASE_URL}/suppliers`, { headers: getHeaders() });
    return res.json();
  },
  getInsurances: async () => {
    const res = await fetch(`${API_BASE_URL}/insurances`, { headers: getHeaders() });
    return res.json();
  }
};

import React, { useState, useEffect } from 'react';
import { ViewState, Drug, Sale, User, UserRole, Supplier, Insurance, PendingOrder } from '../types';
import { INITIAL_DRUGS, INITIAL_USERS, INITIAL_SUPPLIERS, INITIAL_INSURANCES } from './constants';
import Dashboard from './Dashboard';
import Inventory from './Inventory';
import POS from './POS';
import AIAssistant from './AIAssistant';
import PrescriptionScanner from './PrescriptionScanner';
import Login from './Login';
import UserManagement from './UserManagement';
import SalesHistory from './SalesHistory';
import Suppliers from './Suppliers';
import Insurances from './Insurances';
import DataExport from './DataExport';
import Orders from './Orders';
import CashClosing from './CashClosing';
import { apiService } from '../services/apiService';

import { 
  LayoutDashboard, Package, ShoppingCart, Bot, ScanLine, Activity, LogOut, Users, Bell, 
  AlertTriangle, Clock, History, Truck, ShieldCheck, Database, ShoppingBag, Wallet,
  ChevronDown, ChevronRight, Layers, FileText, BrainCircuit, Loader2
} from 'lucide-react';

const App: React.FC = () => {
  // Global State
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  // App Data
  const [drugs, setDrugs] = useState<Drug[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [insurances, setInsurances] = useState<Insurance[]>([]);
  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>([]);

  const [isLoading, setIsLoading] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [showCashClosing, setShowCashClosing] = useState(false);
  const [dismissedNotifications, setDismissedNotifications] = useState<string[]>([]);

  // Fetch data from Laravel
  const loadData = async () => {
    setIsLoading(true);
    try {
      const [drugsData, salesData, suppliersData, insurancesData] = await Promise.all([
        apiService.getDrugs().catch(() => INITIAL_DRUGS), // Fallback to mock for dev
        apiService.getSales().catch(() => []),
        apiService.getSuppliers().catch(() => INITIAL_SUPPLIERS),
        apiService.getInsurances().catch(() => INITIAL_INSURANCES)
      ]);
      setDrugs(drugsData);
      setSales(salesData);
      setSuppliers(suppliersData);
      setInsurances(insurancesData);
    } catch (error) {
      console.error("Failed to load data from Laravel", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (currentUser) {
      loadData();
    }
  }, [currentUser]);

  // Derived state for notifications
  const lowStockItems = drugs.filter(d => d.stock < 20 && !dismissedNotifications.includes(`stock-${d.id}`));
  const expiringItems = drugs.filter(d => {
    if (!d.expiryDate) return false;
    if (dismissedNotifications.includes(`expiry-${d.id}`)) return false;
    const today = new Date();
    const exp = new Date(d.expiryDate);
    const diffTime = exp.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    return diffDays <= 90;
  });

  const totalNotifications = lowStockItems.length + expiringItems.length;

  useEffect(() => {
    if (currentUser) {
      if (currentUser.role === 'CASHIER') setCurrentView(ViewState.POS);
      else if (currentUser.role === 'AGENT') setCurrentView(ViewState.INVENTORY);
      else if (currentUser.role === 'SELLER') setCurrentView(ViewState.POS);
      else setCurrentView(ViewState.DASHBOARD);
    }
  }, [currentUser]);

  const handleSaleComplete = async (sale: Sale) => {
    try {
      const savedSale = await apiService.createSale(sale);
      setSales(prev => [...prev, savedSale]);
      // Refresh drugs to get updated stocks from Laravel
      const updatedDrugs = await apiService.getDrugs();
      setDrugs(updatedDrugs);
    } catch (error) {
      alert("Erreur lors de l'enregistrement de la vente.");
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setShowNotifications(false);
    setDismissedNotifications([]);
  };

  if (!currentUser) {
    return <Login users={users} onLogin={setCurrentUser} />;
  }

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="h-full flex flex-col items-center justify-center text-pharmacy-600">
          <Loader2 className="animate-spin mb-4" size={48} />
          <p className="font-medium">Synchronisation avec Laravel...</p>
        </div>
      );
    }

    switch (currentView) {
      case ViewState.DASHBOARD:
        return currentUser.role === 'ADMIN' ? <Dashboard drugs={drugs} sales={sales} /> : null;
      case ViewState.INVENTORY:
        return ['ADMIN', 'AGENT', 'SELLER'].includes(currentUser.role) ? <Inventory drugs={drugs} setDrugs={setDrugs} currentUser={currentUser} /> : null;
      case ViewState.POS:
        return ['ADMIN', 'CASHIER', 'SELLER'].includes(currentUser.role) ? 
          <POS 
            drugs={drugs} 
            setDrugs={setDrugs} 
            insurances={insurances} 
            onSaleComplete={handleSaleComplete} 
            currentUser={currentUser}
            pendingOrders={pendingOrders}
            setPendingOrders={setPendingOrders}
          /> : null;
      case ViewState.SALES_HISTORY:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <SalesHistory sales={sales} /> : null;
      case ViewState.SUPPLIERS:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <Suppliers suppliers={suppliers} setSuppliers={setSuppliers} /> : null;
      case ViewState.INSURANCES:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <Insurances insurances={insurances} setInsurances={setInsurances} /> : null;
      case ViewState.ASSISTANT:
        return ['ADMIN', 'AGENT', 'SELLER'].includes(currentUser.role) ? 
          <AIAssistant 
            drugs={drugs} 
            sales={sales} 
            suppliers={suppliers} 
            insurances={insurances} 
          /> : null;
      case ViewState.SCANNER:
        return ['ADMIN', 'AGENT', 'SELLER'].includes(currentUser.role) ? <PrescriptionScanner /> : null;
      case ViewState.USERS:
        return currentUser.role === 'ADMIN' ? <UserManagement users={users} setUsers={setUsers} /> : null;
      case ViewState.EXPORTS:
        return currentUser.role === 'ADMIN' ? <DataExport drugs={drugs} sales={sales} users={users} suppliers={suppliers} insurances={insurances} /> : null;
      case ViewState.ORDERS:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <Orders drugs={drugs} suppliers={suppliers} /> : null;
      default:
        return <div>Accès non autorisé</div>;
    }
  };

  const NavItem = ({ view, icon: Icon, label, allowedRoles, isSubItem = false }: { view: ViewState, icon: any, label: string, allowedRoles: UserRole[], isSubItem?: boolean }) => {
    if (!allowedRoles.includes(currentUser.role)) return null;
    return (
      <button
        onClick={() => setCurrentView(view)}
        className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all duration-200 mb-1 ${
          currentView === view 
          ? 'bg-pharmacy-600 text-white shadow-md shadow-pharmacy-200' 
          : 'text-gray-600 hover:bg-pharmacy-50 hover:text-pharmacy-700'
        } ${isSubItem ? 'pl-11 text-sm' : ''}`}
      >
        <Icon size={isSubItem ? 18 : 20} className={currentView === view ? 'text-white' : isSubItem ? 'text-gray-400' : 'text-gray-500'} />
        <span className="font-medium">{label}</span>
      </button>
    );
  };

  const NavGroup = ({ label, icon: Icon, children, allowedRoles }: { label: string, icon: any, children?: React.ReactNode, allowedRoles: UserRole[] }) => {
    const [isOpen, setIsOpen] = useState(false);
    if (!allowedRoles.includes(currentUser.role)) return null;
    return (
      <div className="mb-2">
        <button onClick={() => setIsOpen(!isOpen)} className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-colors duration-200 hover:bg-gray-50 ${isOpen ? 'text-pharmacy-800 bg-gray-50' : 'text-gray-700'}`}>
          <div className="flex items-center space-x-3">
             <Icon size={20} className="text-gray-500" />
             <span className="font-bold text-sm uppercase tracking-wide">{label}</span>
          </div>
          {isOpen ? <ChevronDown size={16} /> : <ChevronRight size={16} />}
        </button>
        <div className={`overflow-hidden transition-all duration-300 ease-in-out ${isOpen ? 'max-h-96 opacity-100 mt-1' : 'max-h-0 opacity-0'}`}>
           {children}
        </div>
      </div>
    );
  };

  return (
    <div className="flex h-screen bg-gray-100 font-sans overflow-hidden">
      {showCashClosing && <CashClosing sales={sales} currentUser={currentUser} onClose={() => setShowCashClosing(false)} />}
      <aside className="w-64 bg-white border-r border-gray-200 flex flex-col shadow-sm z-10">
        <div className="p-6 flex items-center space-x-3 border-b border-gray-100">
          <div className="bg-pharmacy-600 p-2 rounded-lg text-white"><Activity size={24} /></div>
          <div>
            <h1 className="text-xl font-bold text-gray-800 tracking-tight">Fasopharm</h1>
            <p className="text-xs text-gray-400 font-medium">{currentUser.role}</p>
          </div>
        </div>
        <nav className="flex-1 p-3 space-y-1 overflow-y-auto custom-scrollbar">
          <NavItem view={ViewState.DASHBOARD} icon={LayoutDashboard} label="Tableau de Bord" allowedRoles={['ADMIN']} />
          <NavItem view={ViewState.POS} icon={ShoppingCart} label={currentUser.role === 'SELLER' ? "Préparation" : "Caisse"} allowedRoles={['ADMIN', 'CASHIER', 'SELLER']} />
          <NavGroup label="Logistique" icon={Truck} allowedRoles={['ADMIN', 'AGENT', 'SELLER']}>
             <NavItem view={ViewState.INVENTORY} icon={Package} label="Stocks" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} isSubItem />
             <NavItem view={ViewState.ORDERS} icon={ShoppingBag} label="Réappro" allowedRoles={['ADMIN', 'AGENT']} isSubItem />
             <NavItem view={ViewState.SUPPLIERS} icon={Layers} label="Fournisseurs" allowedRoles={['ADMIN', 'AGENT']} isSubItem />
          </NavGroup>
          <NavGroup label="Gestion" icon={FileText} allowedRoles={['ADMIN', 'AGENT']}>
             <NavItem view={ViewState.SALES_HISTORY} icon={History} label="Historique" allowedRoles={['ADMIN', 'AGENT']} isSubItem />
             <NavItem view={ViewState.INSURANCES} icon={ShieldCheck} label="Assurances" allowedRoles={['ADMIN', 'AGENT']} isSubItem />
             <NavItem view={ViewState.EXPORTS} icon={Database} label="Exports" allowedRoles={['ADMIN']} isSubItem />
             <NavItem view={ViewState.USERS} icon={Users} label="Utilisateurs" allowedRoles={['ADMIN']} isSubItem />
          </NavGroup>
          <NavGroup label="IA" icon={BrainCircuit} allowedRoles={['ADMIN', 'AGENT', 'SELLER']}>
             <NavItem view={ViewState.ASSISTANT} icon={Bot} label="Assistant" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} isSubItem />
             <NavItem view={ViewState.SCANNER} icon={ScanLine} label="Scan" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} isSubItem />
          </NavGroup>
        </nav>
        <div className="p-4 border-t border-gray-100">
          <button onClick={handleLogout} className="w-full flex items-center justify-center space-x-2 p-2 text-red-600 hover:bg-red-50 rounded-lg transition">
            <LogOut size={18} /><span className="text-sm font-medium">Déconnexion</span>
          </button>
        </div>
      </aside>
      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-16 bg-white border-b border-gray-200 flex items-center justify-between px-6 shadow-sm">
          <h2 className="text-xl font-bold text-gray-800">{currentView}</h2>
          <div className="flex items-center space-x-4">
             {['ADMIN', 'CASHIER'].includes(currentUser.role) && (
               <button onClick={() => setShowCashClosing(true)} className="flex items-center gap-2 px-3 py-1.5 bg-pharmacy-100 text-pharmacy-700 rounded-lg text-sm font-bold hover:bg-pharmacy-200 transition">
                   <Wallet size={16} /><span>Caisse</span>
               </button>
             )}
            <div className="relative">
              <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 text-gray-500 hover:bg-gray-100 rounded-full relative">
                <Bell size={20} />
                {totalNotifications > 0 && <span className="absolute top-0 right-0 h-4 w-4 bg-red-500 rounded-full border-2 border-white flex items-center justify-center text-[10px] text-white font-bold">{totalNotifications}</span>}
              </button>
            </div>
          </div>
        </header>
        <div className="flex-1 overflow-hidden relative">{renderContent()}</div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Drug, User } from '../types';
import { Plus, Search, Trash2, Edit2, Package, Calendar, ScanLine, Loader2, Camera, Lock } from 'lucide-react';
import { analyzeMedicineBox } from '../services/geminiService';
import { apiService } from '../services/apiService';

interface InventoryProps {
  drugs: Drug[];
  setDrugs: React.Dispatch<React.SetStateAction<Drug[]>>;
  currentUser: User;
}

const Inventory: React.FC<InventoryProps> = ({ drugs, setDrugs, currentUser }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingDrug, setEditingDrug] = useState<Drug | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const canAdd = currentUser.role === 'ADMIN' || currentUser.role === 'AGENT';
  const canEdit = currentUser.role === 'ADMIN';
  const canDelete = currentUser.role === 'ADMIN';

  const [formData, setFormData] = useState<Partial<Drug>>({
    name: '',
    description: '',
    category: '',
    dosage: '',
    price: 0,
    stock: 0,
    expiryDate: ''
  });

  const handleOpenModal = (drug?: Drug) => {
    if (drug && !canEdit) return;
    if (!drug && !canAdd) return;

    if (drug) {
      setEditingDrug(drug);
      setFormData(drug);
    } else {
      setEditingDrug(null);
      setFormData({ name: '', description: '', category: '', dosage: '', price: 0, stock: 0, expiryDate: '' });
    }
    setIsModalOpen(true);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      const savedDrug = await apiService.saveDrug(formData);
      if (editingDrug) {
        setDrugs(drugs.map(d => d.id === editingDrug.id ? savedDrug : d));
      } else {
        setDrugs([...drugs, savedDrug]);
      }
      setIsModalOpen(false);
    } catch (error) {
      alert("Erreur lors de la sauvegarde sur Laravel.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!canDelete) return;
    if (window.confirm('Confirmer la suppression sur le serveur ?')) {
      try {
        await apiService.deleteDrug(id);
        setDrugs(drugs.filter(d => d.id !== id));
      } catch (error) {
        alert("Erreur lors de la suppression.");
      }
    }
  };

  const handleScanProduct = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setIsScanning(true);
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = reader.result as string;
        const result = await analyzeMedicineBox(base64String);
        if (result) {
          setFormData(prev => ({
            ...prev,
            name: result.name || prev.name,
            description: result.description || prev.description,
            category: result.category || prev.category,
            dosage: result.dosage || prev.dosage
          }));
        } else {
          alert("Impossible de lire les informations.");
        }
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const filteredDrugs = drugs.filter(d => 
    d.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    d.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="p-6 h-full flex flex-col">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800">Gestion des Stocks (Laravel Sync)</h2>
        {canAdd && (
          <button onClick={() => handleOpenModal()} className="bg-pharmacy-600 hover:bg-pharmacy-700 text-white px-4 py-2 rounded-lg flex items-center space-x-2 transition shadow-md">
            <Plus size={20} /><span>Ajouter</span>
          </button>
        )}
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 flex-1 flex flex-col overflow-hidden">
        <div className="p-4 border-b border-gray-100">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
            <input type="text" placeholder="Rechercher..." className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-pharmacy-500" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
        </div>

        <div className="overflow-auto flex-1">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50 sticky top-0">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Produit</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Catégorie</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase">Stock</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredDrugs.map(drug => (
                <tr key={drug.id} className="hover:bg-gray-50 transition">
                  <td className="px-6 py-4">
                    <div className="text-sm font-medium text-gray-900">{drug.name}</div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="px-2 py-1 bg-blue-50 text-blue-700 rounded text-xs">{drug.category}</span>
                  </td>
                  <td className={`px-6 py-4 text-right font-bold ${drug.stock < 20 ? 'text-red-600' : 'text-green-600'}`}>
                    {drug.stock}
                  </td>
                  <td className="px-6 py-4 text-right space-x-2">
                    {canEdit && <button onClick={() => handleOpenModal(drug)} className="text-indigo-600 hover:text-indigo-900"><Edit2 size={18} /></button>}
                    {canDelete && <button onClick={() => handleDelete(drug.id)} className="text-red-600 hover:text-red-900"><Trash2 size={18} /></button>}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 backdrop-blur-sm p-4">
          <div className="bg-white rounded-xl shadow-lg w-full max-w-md p-6 max-h-[90vh] overflow-y-auto">
            <h3 className="text-xl font-bold mb-4">{editingDrug ? 'Modifier' : 'Ajouter'} produit</h3>
            <form onSubmit={handleSave} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700">Nom</label>
                <input required type="text" className="w-full border p-2 rounded" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700">Prix (FCFA)</label>
                  <input required type="number" className="w-full border p-2 rounded" value={formData.price} onChange={e => setFormData({...formData, price: parseFloat(e.target.value)})} />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700">Stock Initial</label>
                  <input required type="number" className="w-full border p-2 rounded" value={formData.stock} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Expiration</label>
                <input required type="date" className="w-full border p-2 rounded" value={formData.expiryDate} onChange={e => setFormData({...formData, expiryDate: e.target.value})} />
              </div>
              <div className="flex justify-end space-x-2 pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="px-4 py-2 bg-gray-200 rounded">Annuler</button>
                <button type="submit" disabled={isSaving} className="px-4 py-2 bg-pharmacy-600 text-white rounded flex items-center gap-2">
                  {isSaving && <Loader2 className="animate-spin" size={16} />}
                  Enregistrer
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;

import React from 'react';
import { Drug, Sale, User, Supplier, Insurance } from '../types';
import { Download, FileSpreadsheet, Database, Shield, AlertTriangle } from 'lucide-react';

interface DataExportProps {
  drugs: Drug[];
  sales: Sale[];
  users: User[];
  suppliers: Supplier[];
  insurances: Insurance[];
}

const DataExport: React.FC<DataExportProps> = ({ drugs, sales, users, suppliers, insurances }) => {

  const downloadCSV = (data: any[], filename: string) => {
    if (!data || data.length === 0) {
      alert("Aucune donnée à exporter.");
      return;
    }

    // Get headers
    const headers = Object.keys(data[0]);

    // Create CSV content with semicolon separator for better Excel compatibility in FR regions
    // We add the UTF-8 BOM (\uFEFF) at the start so Excel recognizes accents correctly
    const BOM = '\uFEFF';
    const csvContent = [
      headers.join(';'), // Header row with semicolon
      ...data.map(row => headers.map(fieldName => {
        let val = row[fieldName] === null || row[fieldName] === undefined ? '' : row[fieldName];
        // Clean values: replace internal semicolons and quotes
        if (typeof val === 'string') {
          val = val.replace(/"/g, '""').replace(/;/g, ',');
          return `"${val}"`;
        }
        return val;
      }).join(';'))
    ].join('\r\n');

    const blob = new Blob([BOM + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);

    link.setAttribute('href', url);
    link.setAttribute('download', `${filename}_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

