            <div className="flex items-center justify-between mb-4 relative z-10">
                <div className="p-3 bg-red-100 text-red-700 rounded-full group-hover:bg-red-200 transition">
                    <AlertTriangle size={24} />
                </div>
                <span className="text-sm font-bold text-red-500">{drugs.filter(d => d.stock < 20).length} alertes</span>
            </div>
            <h3 className="text-lg font-bold text-gray-800 mb-2 relative z-10">Ruptures & Stocks Bas</h3>
