import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { Drug, Sale } from '../types';
import { TrendingUp, AlertTriangle, DollarSign, Package, Award, Trophy, Medal, UserCheck } from 'lucide-react';

interface DashboardProps {
  drugs: Drug[];
  sales: Sale[];
}

const Dashboard: React.FC<DashboardProps> = ({ drugs, sales }) => {
  // 1. Basic Stats Calculation
  const totalRevenue = sales.reduce((acc, sale) => acc + (sale.patientAmount || sale.total), 0);
  const lowStockDrugs = drugs.filter(d => d.stock < 20);
  const totalStock = drugs.reduce((acc, d) => acc + d.stock, 0);

  // 2. Performance Leaders (Vendeur vs Caissier)
  const getLeaders = () => {
    const cashierStats: Record<string, number> = {}; // Par Chiffre d'Affaires
    const sellerStats: Record<string, number> = {};  // Par Nombre de commandes envoyées

    sales.forEach(sale => {
      // Le Caissier est celui qui a validé la vente (servedBy)
      const cashierName = sale.servedBy;
      cashierStats[cashierName] = (cashierStats[cashierName] || 0) + (sale.patientAmount || sale.total);

      // Le Vendeur est celui qui a préparé/envoyé (on utilise servedBy si préparé par lui-même, 
      // ou on pourrait mapper un champ 'preparedBy' si présent dans le modèle Sale)
      // Note: Dans notre flux, le vendeur est identifié dans la commande initiale. 
      // Si le système Laravel stocke le préparateur, on l'utilise. Sinon on se base sur l'activité.
      const sellerName = sale.servedBy; // À remplacer par sale.preparedBy si disponible dans votre API Laravel
      sellerStats[sellerName] = (sellerStats[sellerName] || 0) + 1;
    });

    const bestCashier = Object.entries(cashierStats).sort(([, a], [, b]) => b - a)[0];
    const bestSeller = Object.entries(sellerStats).sort(([, a], [, b]) => b - a)[0];

    return {
      cashier: bestCashier ? { name: bestCashier[0], amount: bestCashier[1] } : null,
      seller: bestSeller ? { name: bestSeller[0], count: bestSeller[1] } : null
    };
  };

  const leaders = getLeaders();

  // 3. Real Weekly Sales Calculation
  const getWeeklyData = () => {
    const days = ['Dim', 'Lun', 'Mar', 'Mer', 'Jeu', 'Ven', 'Sam'];
    const now = new Date();
    const last7DaysMap: Record<string, { name: string, vente: number, sortOrder: number }> = {};

    for (let i = 6; i >= 0; i--) {
      const d = new Date();
      d.setDate(now.getDate() - i);
      const dayName = days[d.getDay()];
      const dateKey = d.toDateString();
      last7DaysMap[dateKey] = { name: dayName, vente: 0, sortOrder: i };
    }

    sales.forEach(sale => {
      const saleDate = new Date(sale.timestamp).toDateString();
      if (last7DaysMap[saleDate]) {
        last7DaysMap[saleDate].vente += (sale.patientAmount || sale.total);
      }
    });

    return Object.values(last7DaysMap).sort((a, b) => b.sortOrder - a.sortOrder);
  };

  const salesData = getWeeklyData();

  // 4. Top Selling Products
  const productSalesCount: Record<string, number> = {};
  sales.forEach(sale => {
    sale.items.forEach(item => {
      productSalesCount[item.name] = (productSalesCount[item.name] || 0) + item.quantity;
    });
  });

  const topProducts = Object.entries(productSalesCount)
    .sort(([, a], [, b]) => b - a)
    .slice(0, 5)
    .map(([name, count]) => ({ name, count }));

  const formatCurrency = (value: number) => {
    return value.toLocaleString('fr-FR') + ' FCFA';
  };

  return (
    <div className="p-6 space-y-6 animate-fade-in h-full overflow-y-auto">
      <h2 className="text-2xl font-bold text-gray-800">Performance de l'Équipe</h2>

