        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex items-center space-x-4 hover:shadow-md transition">
          <div className="p-3 bg-pharmacy-100 text-pharmacy-600 rounded-full"><DollarSign size={24} /></div>
          <div>
            <p className="text-sm text-gray-500">Recettes Réelles</p>
            <p className="text-xl font-bold text-gray-800">{formatCurrency(totalRevenue)}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex items-center space-x-4 hover:shadow-md transition">
          <div className="p-3 bg-red-100 text-red-600 rounded-full"><AlertTriangle size={24} /></div>
          <div>
            <p className="text-sm text-gray-500">Alertes Stock</p>
            <p className="text-xl font-bold text-gray-800">{lowStockDrugs.length} critiques</p>
          </div>
        </div>

        {/* Podium Vendeur (Celui qui envoie les commandes) */}
        <div className="bg-gradient-to-br from-blue-50 to-indigo-50 p-6 rounded-xl shadow-sm border border-blue-100 flex items-center space-x-4">
          <div className="p-3 bg-blue-500 text-white rounded-full shadow-lg"><Medal size={24} /></div>
          <div className="overflow-hidden">
            <p className="text-[10px] font-bold text-blue-700 uppercase tracking-wider">Top Vendeur (Comptoir)</p>
            <p className="text-sm font-bold text-gray-800 truncate">{leaders.seller?.name || "---"}</p>
            <p className="text-xs text-blue-600 font-medium">{leaders.seller ? `${leaders.seller.count} envois` : "0 commande"}</p>
          </div>
        </div>

        {/* Podium Caissier (Celui qui encaisse) */}
        <div className="bg-gradient-to-br from-yellow-50 to-orange-50 p-6 rounded-xl shadow-sm border border-yellow-100 flex items-center space-x-4">
          <div className="p-3 bg-yellow-400 text-white rounded-full shadow-lg"><Trophy size={24} /></div>
          <div className="overflow-hidden">
            <p className="text-[10px] font-bold text-yellow-700 uppercase tracking-wider">Top Caissier (Encaissement)</p>
            <p className="text-sm font-bold text-gray-800 truncate">{leaders.cashier?.name || "---"}</p>
            <p className="text-xs text-yellow-600 font-medium">{leaders.cashier ? formatCurrency(leaders.cashier.amount) : "0 FCFA"}</p>
