            </div>
            <p className="text-lg font-black truncate leading-tight">{leaders.cashier?.name || "---"}</p>
            <p className="text-xs font-medium opacity-90">{leaders.cashier ? formatCurrency(leaders.cashier.amount) : "0 FCFA"}</p>
