import React, { useState, useEffect } from 'react';
import { ViewState, Drug, Sale, User, UserRole, Supplier, Insurance, PendingOrder } from './types';
import { INITIAL_DRUGS, INITIAL_USERS, INITIAL_SUPPLIERS, INITIAL_INSURANCES } from './constants';
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import POS from './components/POS';
import AIAssistant from './components/AIAssistant';
import PrescriptionScanner from './components/PrescriptionScanner';
import Login from './components/Login';
import UserManagement from './components/UserManagement';
import SalesHistory from './components/SalesHistory';
import Suppliers from './components/Suppliers';
import Insurances from './components/Insurances';
import DataExport from './components/DataExport';
import Orders from './components/Orders';
import CashClosing from './components/CashClosing';

import { LayoutDashboard, Package, ShoppingCart, Bot, ScanLine, Activity, LogOut, Users, Bell, AlertTriangle, Clock, History, Truck, ShieldCheck, Database, ShoppingBag, Wallet } from 'lucide-react';

const App: React.FC = () => {
  // Global State
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  // App Data
  const [drugs, setDrugs] = useState<Drug[]>(INITIAL_DRUGS);
  const [sales, setSales] = useState<Sale[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>(INITIAL_SUPPLIERS);
  const [insurances, setInsurances] = useState<Insurance[]>(INITIAL_INSURANCES);
  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>([]);

  const [showNotifications, setShowNotifications] = useState(false);
  const [showCashClosing, setShowCashClosing] = useState(false);
  const [dismissedNotifications, setDismissedNotifications] = useState<string[]>([]);

  // Derived state for notifications
  const lowStockItems = drugs.filter(d => d.stock < 20 && !dismissedNotifications.includes(`stock-${d.id}`));

  const expiringItems = drugs.filter(d => {
    if (!d.expiryDate) return false;
    if (dismissedNotifications.includes(`expiry-${d.id}`)) return false;
    const today = new Date();
    const exp = new Date(d.expiryDate);
    const diffTime = exp.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    return diffDays <= 90;
  });

  const totalNotifications = lowStockItems.length + expiringItems.length;

  useEffect(() => {
    if (currentUser) {
      if (currentUser.role === 'CASHIER') setCurrentView(ViewState.POS);
      else if (currentUser.role === 'AGENT') setCurrentView(ViewState.INVENTORY);
      else if (currentUser.role === 'SELLER') setCurrentView(ViewState.POS);
      else setCurrentView(ViewState.DASHBOARD);
    }
  }, [currentUser]);

  const handleSaleComplete = (sale: Sale) => {
    setSales([...sales, sale]);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setShowNotifications(false);
    setDismissedNotifications([]);
  };

  const handleQuickAdd = (drug: Drug) => {
    // On bascule sur la vue POS et on pourra implémenter une communication par event ou state global 
    // pour que le panier se remplisse. Pour l'instant, on redirige l'utilisateur.
    setCurrentView(ViewState.POS);
    alert(`${drug.name} est suggéré. Veuillez l'ajouter manuellement dans le panier Caisse.`);
  };

  if (!currentUser) {
    return <Login users={users} onLogin={setCurrentUser} />;
  }

  const renderContent = () => {
    switch (currentView) {
      case ViewState.DASHBOARD:
        return currentUser.role === 'ADMIN' ? <Dashboard drugs={drugs} sales={sales} /> : null;
      case ViewState.INVENTORY:
        return ['ADMIN', 'AGENT', 'SELLER'].includes(currentUser.role) ? <Inventory drugs={drugs} setDrugs={setDrugs} currentUser={currentUser} /> : null;
      case ViewState.POS:
        return ['ADMIN', 'CASHIER', 'SELLER'].includes(currentUser.role) ? 
          <POS 
            drugs={drugs} 
            setDrugs={setDrugs} 
            insurances={insurances} 
            onSaleComplete={handleSaleComplete} 
            currentUser={currentUser}
            pendingOrders={pendingOrders}
            setPendingOrders={setPendingOrders}
          /> : null;
      case ViewState.SALES_HISTORY:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <SalesHistory sales={sales} /> : null;
      case ViewState.SUPPLIERS:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <Suppliers suppliers={suppliers} setSuppliers={setSuppliers} /> : null;
      case ViewState.INSURANCES:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <Insurances insurances={insurances} setInsurances={setInsurances} /> : null;
      case ViewState.ASSISTANT:
        return ['ADMIN', 'AGENT', 'SELLER'].includes(currentUser.role) ? 
          <AIAssistant 
            drugs={drugs} 
            sales={sales} 
            suppliers={suppliers} 
            insurances={insurances} 
            onAddToCart={handleQuickAdd}
          /> : null;
      case ViewState.SCANNER:
        return ['ADMIN', 'AGENT', 'SELLER'].includes(currentUser.role) ? <PrescriptionScanner /> : null;
      case ViewState.USERS:
        return currentUser.role === 'ADMIN' ? <UserManagement users={users} setUsers={setUsers} /> : null;
      case ViewState.EXPORTS:
        return currentUser.role === 'ADMIN' ? <DataExport drugs={drugs} sales={sales} users={users} suppliers={suppliers} insurances={insurances} /> : null;
      case ViewState.ORDERS:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <Orders drugs={drugs} suppliers={suppliers} /> : null;
      default:
        return <div>Accès non autorisé</div>;
    }
  };

  const NavItem = ({ view, icon: Icon, label, allowedRoles }: { view: ViewState, icon: any, label: string, allowedRoles: UserRole[] }) => {
    if (!allowedRoles.includes(currentUser.role)) return null;
    return (
      <button
        onClick={() => setCurrentView(view)}
        className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all duration-200 ${
          currentView === view 
          ? 'bg-pharmacy-600 text-white shadow-lg shadow-pharmacy-200' 
          : 'text-gray-600 hover:bg-pharmacy-50 hover:text-pharmacy-700'
        }`}
      >
        <Icon size={20} />
        <span className="font-medium">{label}</span>
      </button>
    );
  };

  return (
    <div className="flex h-screen bg-gray-100 font-sans overflow-hidden">
      {showCashClosing && <CashClosing sales={sales} currentUser={currentUser} onClose={() => setShowCashClosing(false)} />}
      <aside className="w-64 bg-white border-r border-gray-200 flex flex-col shadow-sm z-10">
        <div className="p-6 flex items-center space-x-3 border-b border-gray-100">
          <div className="bg-pharmacy-600 p-2 rounded-lg text-white"><Activity size={24} /></div>
          <div>
            <h1 className="text-xl font-bold text-gray-800 tracking-tight">Fasopharm</h1>
            <p className="text-xs text-gray-400 font-medium">
              {currentUser.role}
            </p>
          </div>
        </div>
        <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
          <div className="px-4 py-2 text-xs font-semibold text-gray-400 uppercase tracking-wider">Gestion</div>
          <NavItem view={ViewState.DASHBOARD} icon={LayoutDashboard} label="Tableau de Bord" allowedRoles={['ADMIN']} />
          <NavItem view={ViewState.INVENTORY} icon={Package} label="Stocks" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} />
          <NavItem view={ViewState.ORDERS} icon={ShoppingBag} label="Réappro" allowedRoles={['ADMIN', 'AGENT']} />
          <NavItem view={ViewState.POS} icon={ShoppingCart} label={currentUser.role === 'SELLER' ? "Préparation" : "Caisse"} allowedRoles={['ADMIN', 'CASHIER', 'SELLER']} />
          {['ADMIN', 'AGENT'].includes(currentUser.role) && (
             <>
               <NavItem view={ViewState.SALES_HISTORY} icon={History} label="Historique Ventes" allowedRoles={['ADMIN', 'AGENT']} />
               <NavItem view={ViewState.SUPPLIERS} icon={Truck} label="Fournisseurs" allowedRoles={['ADMIN', 'AGENT']} />
               <NavItem view={ViewState.INSURANCES} icon={ShieldCheck} label="Assurances" allowedRoles={['ADMIN', 'AGENT']} />
             </>
          )}
          {['ADMIN', 'AGENT', 'SELLER'].includes(currentUser.role) && (
            <>
              <div className="mt-8 px-4 py-2 text-xs font-semibold text-gray-400 uppercase tracking-wider">IA & Outils</div>
              <NavItem view={ViewState.ASSISTANT} icon={Bot} label="Assistant & Ordo" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} />
              <NavItem view={ViewState.SCANNER} icon={ScanLine} label="Scan Ordonnance" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} />
            </>
          )}
          {currentUser.role === 'ADMIN' && (
             <>
              <div className="mt-8 px-4 py-2 text-xs font-semibold text-gray-400 uppercase tracking-wider">Administration</div>
              <NavItem view={ViewState.USERS} icon={Users} label="Utilisateurs" allowedRoles={['ADMIN']} />
              <NavItem view={ViewState.EXPORTS} icon={Database} label="Données & Exports" allowedRoles={['ADMIN']} />
             </>
          )}
        </nav>
        <div className="p-4 border-t border-gray-100">
          <button onClick={handleLogout} className="w-full flex items-center justify-center space-x-2 p-2 text-red-600 hover:bg-red-50 rounded-lg transition">
            <LogOut size={18} /><span className="text-sm font-medium">Déconnexion</span>
          </button>
        </div>
      </aside>
      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-16 bg-white border-b border-gray-200 flex items-center justify-between px-6 shadow-sm">
          <h2 className="text-xl font-bold text-gray-800">{currentView}</h2>
          <div className="flex items-center space-x-4">
             {['ADMIN', 'CASHIER'].includes(currentUser.role) && (
               <button onClick={() => setShowCashClosing(true)} className="flex items-center gap-2 px-3 py-1.5 bg-pharmacy-100 text-pharmacy-700 rounded-lg text-sm font-bold hover:bg-pharmacy-200 transition">
                   <Wallet size={16} /><span>Caisse</span>
               </button>
             )}
            <div className="relative">
              <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 text-gray-500 hover:bg-gray-100 rounded-full relative transition-colors outline-none">
                <Bell size={20} />
                {totalNotifications > 0 && <span className="absolute top-0 right-0 h-4 w-4 bg-red-500 rounded-full border-2 border-white flex items-center justify-center text-[10px] text-white font-bold">{totalNotifications}</span>}
              </button>
            </div>
          </div>
        </header>
        <div className="flex-1 overflow-hidden relative">{renderContent()}</div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ViewState, Drug, Sale, User, UserRole, Supplier, Insurance, PendingOrder, CartItem } from './types';
import { INITIAL_DRUGS, INITIAL_USERS, INITIAL_SUPPLIERS, INITIAL_INSURANCES } from './constants';
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import POS from './components/POS';
import AIAssistant from './components/AIAssistant';
import PrescriptionScanner from './components/PrescriptionScanner';
import Login from './components/Login';
import UserManagement from './components/UserManagement';
import SalesHistory from './components/SalesHistory';
import Suppliers from './components/Suppliers';
import Insurances from './components/Insurances';
import DataExport from './components/DataExport';
import Orders from './components/Orders';
import CashClosing from './components/CashClosing';
import { apiService } from './services/apiService';

import { 
  LayoutDashboard, Package, ShoppingCart, Bot, ScanLine, Activity, LogOut, Users, Bell, 
  AlertTriangle, Clock, History, Truck, ShieldCheck, Database, ShoppingBag, Wallet,
  ChevronDown, ChevronRight, Layers, FileText, BrainCircuit, Loader2
} from 'lucide-react';

const App: React.FC = () => {
  // Global State
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  // App Data
  const [drugs, setDrugs] = useState<Drug[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [insurances, setInsurances] = useState<Insurance[]>([]);
  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>([]);

  // New State for AI Bridge
  const [aiSelectedItems, setAiSelectedItems] = useState<Drug[]>([]);

  const [isLoading, setIsLoading] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [showCashClosing, setShowCashClosing] = useState(false);
  const [dismissedNotifications, setDismissedNotifications] = useState<string[]>([]);

  // Fetch data from Laravel
  const loadData = async () => {
    setIsLoading(true);
    try {
      const [drugsData, salesData, suppliersData, insurancesData] = await Promise.all([
        apiService.getDrugs().catch(() => INITIAL_DRUGS),
        apiService.getSales().catch(() => []),
        apiService.getSuppliers().catch(() => INITIAL_SUPPLIERS),
        apiService.getInsurances().catch(() => INITIAL_INSURANCES)
      ]);
      setDrugs(drugsData);
      setSales(salesData);
      setSuppliers(suppliersData);
      setInsurances(insurancesData);
    } catch (error) {
      console.error("Failed to load data from Laravel", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (currentUser) {
      loadData();
    }
  }, [currentUser]);

  const handleSaleComplete = async (sale: Sale) => {
    try {
      const savedSale = await apiService.createSale(sale);
      setSales(prev => [...prev, savedSale]);
      const updatedDrugs = await apiService.getDrugs();
      setDrugs(updatedDrugs);
    } catch (error) {
      alert("Erreur lors de l'enregistrement de la vente.");
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setShowNotifications(false);
    setDismissedNotifications([]);
    setAiSelectedItems([]);
  };

  // Improved QuickAdd: Store item globally and redirect
  const handleQuickAddFromAI = (drug: Drug) => {
    setAiSelectedItems(prev => [...prev, drug]);
    // Notification visuelle légère ou redirection
    setCurrentView(ViewState.POS);
  };

  if (!currentUser) {
    return <Login users={users} onLogin={setCurrentUser} />;
  }

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="h-full flex flex-col items-center justify-center text-pharmacy-600">
          <Loader2 className="animate-spin mb-4" size={48} />
          <p className="font-medium">Synchronisation avec Laravel...</p>
        </div>
      );
    }

    switch (currentView) {
      case ViewState.DASHBOARD:
        return currentUser.role === 'ADMIN' ? <Dashboard drugs={drugs} sales={sales} /> : null;
      case ViewState.INVENTORY:
        return ['ADMIN', 'AGENT', 'SELLER'].includes(currentUser.role) ? <Inventory drugs={drugs} setDrugs={setDrugs} currentUser={currentUser} /> : null;
      case ViewState.POS:
        return ['ADMIN', 'CASHIER', 'SELLER'].includes(currentUser.role) ? 
          <POS 
            drugs={drugs} 
            setDrugs={setDrugs} 
            insurances={insurances} 
            onSaleComplete={handleSaleComplete} 
            currentUser={currentUser}
            pendingOrders={pendingOrders}
            setPendingOrders={setPendingOrders}
            aiIncomingItems={aiSelectedItems}
            onClearIncomingAI={() => setAiSelectedItems([])}
          /> : null;
      case ViewState.SALES_HISTORY:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <SalesHistory sales={sales} /> : null;
      case ViewState.SUPPLIERS:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <Suppliers suppliers={suppliers} setSuppliers={setSuppliers} /> : null;
      case ViewState.INSURANCES:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <Insurances insurances={insurances} setInsurances={setInsurances} /> : null;
      case ViewState.ASSISTANT:
        return ['ADMIN', 'AGENT', 'SELLER'].includes(currentUser.role) ? 
          <AIAssistant 
            drugs={drugs} 
            sales={sales} 
            suppliers={suppliers} 
            insurances={insurances} 
            onAddToCart={handleQuickAddFromAI}
          /> : null;
      case ViewState.SCANNER:
        return ['ADMIN', 'AGENT', 'SELLER'].includes(currentUser.role) ? <PrescriptionScanner /> : null;
      case ViewState.USERS:
        return currentUser.role === 'ADMIN' ? <UserManagement users={users} setUsers={setUsers} /> : null;
      case ViewState.EXPORTS:
        return currentUser.role === 'ADMIN' ? <DataExport drugs={drugs} sales={sales} users={users} suppliers={suppliers} insurances={insurances} /> : null;
      case ViewState.ORDERS:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <Orders drugs={drugs} suppliers={suppliers} /> : null;
      default:
        return <div>Accès non autorisé</div>;
