                   <Wallet size={16} /><span>Caisse</span>
               </button>
             )}
            <div className="relative">
              <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 text-gray-500 hover:bg-gray-100 rounded-full relative">
                <Bell size={20} />
                {totalNotifications > 0 && <span className="absolute top-0 right-0 h-4 w-4 bg-red-500 rounded-full border-2 border-white flex items-center justify-center text-[10px] text-white font-bold">{totalNotifications}</span>}
              </button>
            </div>
          </div>
        </header>
        <div className="flex-1 overflow-hidden relative">{renderContent()}</div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Drug, CartItem, Sale, PaymentMethod, User, Insurance, PendingOrder } from '../types';
import { ShoppingCart, Plus, Minus, Trash, Search, AlertOctagon, CreditCard, Banknote, Smartphone, Printer, CheckCircle, ShieldCheck, Camera, Loader2, User as UserIcon, FileText, Send, Clock, X, RefreshCw, ChevronDown, ChevronUp, Coins, Sparkles } from 'lucide-react';
import { checkDrugInteractions, analyzeMedicineBox } from '../services/geminiService';

interface POSProps {
  drugs: Drug[];
  setDrugs: React.Dispatch<React.SetStateAction<Drug[]>>;
  insurances: Insurance[];
  onSaleComplete: (sale: Sale) => void;
  currentUser: User;
  pendingOrders: PendingOrder[];
  setPendingOrders: React.Dispatch<React.SetStateAction<PendingOrder[]>>;
  aiIncomingItems?: Drug[];
  onClearIncomingAI?: () => void;
}

const POS: React.FC<POSProps> = ({ 
  drugs, 
  setDrugs, 
  insurances, 
  onSaleComplete, 
  currentUser, 
  pendingOrders, 
  setPendingOrders,
  aiIncomingItems = [],
  onClearIncomingAI
}) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [interactionAlert, setInteractionAlert] = useState<string | null>(null);
  const [isChecking, setIsChecking] = useState(false);
  const [isScanning, setIsScanning] = useState(false);

  // Bridge effect for AI suggestions
  useEffect(() => {
    if (aiIncomingItems.length > 0) {
      const newItems = [...cart];
      aiIncomingItems.forEach(drug => {
        const existing = newItems.find(item => item.id === drug.id);
        if (existing) {
          existing.quantity += 1;
        } else {
          newItems.push({ ...drug, quantity: 1 });
        }
      });
      setCart(newItems);
      if (onClearIncomingAI) onClearIncomingAI();
    }
  }, [aiIncomingItems]);

  // Insurance State
  const [showInsurance, setShowInsurance] = useState(false);
  const [selectedInsuranceId, setSelectedInsuranceId] = useState<string>('');
  const [coverageRate, setCoverageRate] = useState<number>(0);

  // Patient Info State (for Insurance)
  const [patientName, setPatientName] = useState('');
  const [policyNumber, setPolicyNumber] = useState('');

  // Payment State
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('CASH');
  const [amountReceived, setAmountReceived] = useState<number | ''>(''); 

  const [showReceipt, setShowReceipt] = useState<Sale | null>(null);
  const [showPendingTicket, setShowPendingTicket] = useState<PendingOrder | null>(null);

  // Determine Mode
  const isPreparer = currentUser.role === 'SELLER' || currentUser.role === 'AGENT';
  const isCashier = currentUser.role === 'CASHIER' || currentUser.role === 'ADMIN';

  // Refs for auto-focus
  const searchInputRef = useRef<HTMLInputElement>(null);
  const cashInputRef = useRef<HTMLInputElement>(null);

  // Derived calculations
  const totalAmount = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const insuranceAmount = selectedInsuranceId ? Math.round(totalAmount * (coverageRate / 100)) : 0;
  const patientAmount = totalAmount - insuranceAmount;

  // Change Logic
  const amountToPay = patientAmount; 
  const changeDue = typeof amountReceived === 'number' ? amountReceived - amountToPay : 0;
  const isAmountSufficient = paymentMethod !== 'CASH' || (typeof amountReceived === 'number' && amountReceived >= amountToPay);

  useEffect(() => {
    if (searchInputRef.current) searchInputRef.current.focus();
  }, []);

  useEffect(() => {
    if (paymentMethod === 'CASH' && cart.length > 0 && cashInputRef.current) {
        cashInputRef.current.focus();
    }
  }, [paymentMethod, cart.length]);

  const handleInsuranceChange = (id: string) => {
    setSelectedInsuranceId(id);
    if (id) {
      const ins = insurances.find(i => i.id === id);
      setCoverageRate(ins ? ins.defaultCoverage : 0);
    } else {
      setCoverageRate(0);
      setPatientName('');
      setPolicyNumber('');
    }
  };

  const addToCart = (drug: Drug) => {
    const existing = cart.find(item => item.id === drug.id);
    if (existing) {
      if (existing.quantity < drug.stock) {
        setCart(cart.map(item => item.id === drug.id ? { ...item, quantity: item.quantity + 1 } : item));
      } else {
        alert("Stock insuffisant !");
      }
    } else {
      if (drug.stock > 0) {
        setCart([...cart, { ...drug, quantity: 1 }]);
      } else {
        alert("Produit en rupture de stock.");
      }
    }
    setSearchTerm('');
    if (searchInputRef.current) searchInputRef.current.focus();
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        const drug = drugs.find(d => d.id === id);
        if (newQty > 0 && drug && newQty <= drug.stock) {
          return { ...item, quantity: newQty };
        }
      }
      return item;
    }));
  };

  const clearCart = () => {
      if (window.confirm("Voulez-vous vraiment annuler la préparation et vider le panier ?")) {
          setCart([]);
          setSelectedInsuranceId('');
          setPatientName('');
          setPolicyNumber('');
          setAmountReceived('');
      }
  };

  const checkInteractions = async () => {
    if (cart.length < 2) return;
    setIsChecking(true);
    setInteractionAlert(null);
    const names = cart.map(c => c.name);
    const result = await checkDrugInteractions(names);
    setInteractionAlert(result);
    setIsChecking(false);
  };

  const handleCameraScan = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setIsScanning(true);
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = reader.result as string;
        try {
          const result = await analyzeMedicineBox(base64String);
          if (result && result.name) {
            const scannedName = result.name.toLowerCase();
            const foundDrug = drugs.find(d => 
              d.name.toLowerCase().includes(scannedName) || 
              scannedName.includes(d.name.toLowerCase())
            );
            if (foundDrug) {
              addToCart(foundDrug);
            } else {
              alert(`Produit identifié comme "${result.name}" mais non trouvé dans le stock.`);
            }
          } else {
            alert("Impossible d'identifier le produit sur l'image.");
          }
        } catch (error) {
          console.error("Scan error", error);
          alert("Erreur lors de l'analyse.");
        }
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSendToCashier = () => {
    if (cart.length === 0) return;
    const newOrder: PendingOrder = {
      id: Date.now().toString(),
      ticketNumber: `A-${Math.floor(Math.random() * 900) + 100}`,
      timestamp: new Date(),
      items: [...cart],
      total: totalAmount,
      preparedBy: currentUser.fullName,
      insuranceId: selectedInsuranceId,
      patientName,
      policyNumber
    };
    setPendingOrders(prev => [...prev, newOrder]);
    setCart([]);
    setSelectedInsuranceId('');
    setCoverageRate(0);
    setPatientName('');
    setPolicyNumber('');
    setAmountReceived('');
    setShowPendingTicket(newOrder);
  };

  const loadPendingOrder = (order: PendingOrder) => {
    setCart(order.items);
    if (order.insuranceId) {
       setShowInsurance(true);
       handleInsuranceChange(order.insuranceId);
       setPatientName(order.patientName || '');
       setPolicyNumber(order.policyNumber || '');
    }
    setPendingOrders(prev => prev.filter(o => o.id !== order.id));
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;

    if (selectedInsuranceId) {
      if (!patientName.trim() || !policyNumber.trim()) {
        alert("Veuillez entrer les informations du patient assuré.");
        return;
      }
    }

    if (!isAmountSufficient) {
       alert("Le montant reçu est insuffisant.");
       return;
    }

    const newDrugs = drugs.map(d => {
      const cartItem = cart.find(c => c.id === d.id);
      if (cartItem) {
        return { ...d, stock: d.stock - cartItem.quantity };
      }
      return d;
    });
    setDrugs(newDrugs);

    const selectedIns = insurances.find(i => i.id === selectedInsuranceId);
    const sale: Sale = {
      id: Date.now().toString(),
      timestamp: new Date(),
      items: [...cart],
      total: totalAmount,
      paymentMethod: paymentMethod,
      servedBy: currentUser.fullName,
      insuranceId: selectedInsuranceId || undefined,
      insuranceName: selectedIns?.name,
      insuranceCoverageRate: selectedInsuranceId ? coverageRate : undefined,
      insuranceAmount: selectedInsuranceId ? insuranceAmount : 0,
      patientAmount: patientAmount,
      patientName: selectedInsuranceId ? patientName : undefined,
      policyNumber: selectedInsuranceId ? policyNumber : undefined,
      amountReceived: paymentMethod === 'CASH' && typeof amountReceived === 'number' ? amountReceived : undefined,
      changeGiven: paymentMethod === 'CASH' ? changeDue : undefined
    };

    onSaleComplete(sale);
    setCart([]);
    setInteractionAlert(null);
    setSelectedInsuranceId('');
    setCoverageRate(0);
    setPatientName('');
    setPolicyNumber('');
    setAmountReceived('');
    setShowInsurance(false);
    setShowReceipt(sale);
  };

  const filteredDrugs = drugs.filter(d => d.name.toLowerCase().includes(searchTerm.toLowerCase()));
  const formatCurrency = (value: number) => value.toLocaleString('fr-FR') + ' FCFA';

  const PendingTicketModal = () => {
      if (!showPendingTicket) return null;
      return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-60 backdrop-blur-sm animate-fade-in">
            <div className="bg-white p-6 rounded-xl shadow-2xl w-80 text-center">
                <div className="w-16 h-16 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4">
                    <CheckCircle size={32} />
                </div>
                <h3 className="text-xl font-bold text-gray-800">Commande Envoyée !</h3>
                <div className="bg-gray-100 p-4 rounded-lg border border-dashed border-gray-300 my-6">
                    <p className="text-xs text-gray-500 uppercase">Numéro Ticket</p>
                    <p className="text-4xl font-mono font-bold text-gray-900">{showPendingTicket.ticketNumber}</p>
                </div>
                <button onClick={() => setShowPendingTicket(null)} className="w-full py-3 bg-pharmacy-600 text-white rounded-lg hover:bg-pharmacy-700 font-bold">
                    OK
                </button>
            </div>
        </div>
      );
  }

  const ReceiptModal = () => {
    if (!showReceipt) return null;
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-60 backdrop-blur-sm animate-fade-in">
        <div className="bg-white rounded-lg shadow-2xl w-96 overflow-hidden flex flex-col max-h-[90vh]">
          <div className="bg-pharmacy-600 text-white p-4 text-center">
            <div className="mx-auto bg-white/20 rounded-full w-12 h-12 flex items-center justify-center mb-2">
              <Printer size={24} />
            </div>
            <h3 className="font-bold text-lg">Impression Reçu</h3>
          </div>

          <div className="p-6 bg-white font-mono text-sm overflow-y-auto flex-1">
            <div className="text-center mb-4">
              <p className="font-bold text-xl uppercase tracking-wider">Fasopharm</p>
              <p className="text-xs text-gray-500">Ouagadougou, Burkina Faso</p>
            </div>

            <div className="border-b border-dashed border-gray-300 my-4"></div>

            <div className="flex justify-between text-xs mb-2">
              <span>Date: {new Date(showReceipt.timestamp).toLocaleDateString()}</span>
              <span>{new Date(showReceipt.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
            </div>

            {showReceipt.insuranceName && (
              <div className="my-3 border border-gray-300 p-2 rounded text-xs bg-gray-50">
                <p className="font-bold">TIERS-PAYANT: {showReceipt.insuranceName}</p>
                <p>Patient: {showReceipt.patientName}</p>
                <p>Matricule: {showReceipt.policyNumber}</p>
              </div>
            )}

            <div className="space-y-2 mb-4">
              {showReceipt.items.map((item, idx) => (
                <div key={idx} className="flex justify-between">
                  <span>{item.quantity} x {item.name}</span>
                  <span>{formatCurrency(item.price * item.quantity)}</span>
                </div>
              ))}
            </div>

            <div className="border-b border-dashed border-gray-300 my-4"></div>

            <div className="flex justify-between font-bold text-gray-600 my-1">
              <span>Total</span>
              <span>{formatCurrency(showReceipt.total)}</span>
            </div>

            {showReceipt.insuranceName && (
               <div className="flex justify-between text-gray-600 my-1">
                   <span>Part Assurance ({showReceipt.insuranceCoverageRate}%)</span>
                   <span>-{formatCurrency(showReceipt.insuranceAmount || 0)}</span>
               </div>
            )}

            <div className="flex justify-between font-bold text-xl my-2 text-gray-900 pt-2 border-t border-gray-200">
              <span>NET À PAYER</span>
              <span>{formatCurrency(showReceipt.patientAmount || showReceipt.total)}</span>
            </div>

             {showReceipt.paymentMethod === 'CASH' && showReceipt.amountReceived !== undefined && (
                <div className="mt-2 text-right">
                  <div className="text-xs text-gray-500">Espèces Reçu: {formatCurrency(showReceipt.amountReceived)}</div>
                  <div className="font-bold text-gray-800">Monnaie: {formatCurrency(showReceipt.changeGiven || 0)}</div>
                </div>
             )}

            <div className="text-center mt-8 text-xs text-gray-400">
              <p>*** Merci de votre visite ***</p>
            </div>
          </div>

          <div className="p-4 bg-gray-50 flex space-x-3 border-t border-gray-200">
             <button onClick={() => setShowReceipt(null)} className="flex-1 py-3 bg-gray-200 text-gray-800 rounded-lg hover:bg-gray-300 font-bold">Fermer</button>
             <button onClick={() => { window.print(); setShowReceipt(null); }} className="flex-1 py-3 bg-pharmacy-600 text-white rounded-lg hover:bg-pharmacy-700 font-bold flex justify-center items-center gap-2">
               <Printer size={18} /> Imprimer
             </button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="flex h-full bg-gray-100 overflow-hidden relative">
      {showReceipt && <ReceiptModal />}
      {showPendingTicket && <PendingTicketModal />}

      {isCashier && pendingOrders.length > 0 && (
          <div className="w-64 bg-white border-r border-gray-200 flex flex-col z-20 shadow-lg">
              <div className="p-4 bg-orange-50 border-b border-orange-100 flex items-center justify-between">
                  <h3 className="font-bold text-orange-800 flex items-center gap-2 text-sm">
                      <Clock size={16} /> File d'Attente
                  </h3>
                  <span className="bg-orange-200 text-orange-800 text-xs px-2 py-1 rounded-full">{pendingOrders.length}</span>
              </div>
              <div className="flex-1 overflow-y-auto p-2 space-y-2">
                  {pendingOrders.map(order => (
                      <div 
                        key={order.id} 
                        onClick={() => loadPendingOrder(order)}
                        className="p-3 bg-white border border-gray-200 rounded-lg hover:border-orange-400 hover:shadow-md cursor-pointer transition relative group"
                      >
                          <div className="flex justify-between items-start mb-2">
                              <span className="font-mono font-bold text-gray-800 bg-gray-100 px-2 py-0.5 rounded text-lg">{order.ticketNumber}</span>
                              <span className="text-xs text-gray-400">{new Date(order.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                          </div>
                          <div className="flex justify-between items-end">
                              <div className="text-xs text-gray-500">
                                {order.items.length} art. <br/>
                                <span className="italic">par {order.preparedBy.split(' ')[0]}</span>
                              </div>
                              <span className="font-bold text-pharmacy-600">{formatCurrency(order.total)}</span>
                          </div>
                      </div>
                  ))}
              </div>
          </div>
      )}

      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="p-4 bg-white border-b border-gray-200 shadow-sm z-10">
           <div className="flex gap-4 max-w-4xl mx-auto">
              <div className="relative flex-1">
                <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
                <input 
                  ref={searchInputRef}
                  type="text" 
                  placeholder="Rechercher (Nom, Catégorie)..." 
                  className="w-full pl-12 pr-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-pharmacy-500 text-lg shadow-sm"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
              <label className={`flex items-center gap-2 px-6 py-3 rounded-xl cursor-pointer transition border border-gray-300 shadow-sm ${isScanning ? 'bg-gray-100 text-gray-400' : 'bg-white text-gray-700 hover:bg-gray-50'}`}>
                 {isScanning ? <Loader2 className="animate-spin" size={20} /> : <Camera size={20} />}
                 <span className="font-bold hidden md:inline">{isScanning ? '...' : 'Scan'}</span>
                 <input type="file" accept="image/*" className="hidden" onChange={handleCameraScan} disabled={isScanning} />
              </label>
           </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 bg-gray-50">
           <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4 max-w-6xl mx-auto pb-20">
              {filteredDrugs.map(drug => (
                <div key={drug.id} 
                  onClick={() => addToCart(drug)}
                  className={`bg-white p-4 rounded-xl border transition shadow-sm hover:shadow-lg cursor-pointer flex flex-col justify-between h-48 group select-none relative overflow-hidden ${drug.stock === 0 ? 'opacity-50 border-gray-200 pointer-events-none' : 'border-gray-100 hover:border-pharmacy-400'}`}
                >
                  {drug.stock < 20 && drug.stock > 0 && (
                      <div className="absolute top-0 right-0 bg-red-500 text-white text-[10px] px-2 py-0.5 rounded-bl-lg font-bold">
                          Stock Bas
                      </div>
                  )}
                  <div>
                    <h3 className="font-bold text-gray-800 leading-tight mb-1">{drug.name}</h3>
                    <p className="text-xs text-gray-500">{drug.category}</p>
                    <p className="text-xs text-gray-400">{drug.dosage}</p>
                  </div>
                  <div className="mt-2">
                    <div className="flex justify-between items-end">
                      <span className="font-bold text-pharmacy-600 text-xl">{formatCurrency(drug.price).split(' ')[0]} <span className="text-xs text-gray-400">FCFA</span></span>
                    </div>
                    <div className={`text-xs mt-1 font-medium ${drug.stock > 0 ? 'text-green-600' : 'text-red-500'}`}>
                       {drug.stock > 0 ? `${drug.stock} en stock` : 'Rupture'}
                    </div>
                  </div>
                  <div className="absolute inset-0 bg-pharmacy-600 bg-opacity-0 group-hover:bg-opacity-5 transition duration-200 pointer-events-none"></div>
                </div>
              ))}
           </div>
        </div>
      </div>

      <div className="w-[420px] bg-white border-l border-gray-200 shadow-2xl flex flex-col h-full z-30">

          <div className="p-4 bg-gray-800 text-white flex justify-between items-center shadow-md">
             <div className="flex items-center gap-2">
                <ShoppingCart size={20} />
                <span className="font-bold text-lg">{isPreparer && !isCashier ? 'Préparation' : 'Panier'}</span>
                <span className="bg-gray-600 px-2 py-0.5 rounded-full text-xs">{cart.length}</span>
             </div>
             {cart.length > 0 && (
                 <button onClick={clearCart} className="text-gray-400 hover:text-white transition" title="Vider le panier">
                     <Trash size={18} />
                 </button>
             )}
          </div>

          <div className="flex-1 overflow-y-auto p-2 space-y-2 bg-gray-50">
             {cart.length === 0 ? (
               <div className="h-full flex flex-col items-center justify-center text-gray-400 space-y-4 opacity-50">
                 <ShoppingCart size={64} strokeWidth={1} />
                 <p className="font-medium">Scanner ou cliquer pour ajouter</p>
               </div>
             ) : (
               cart.map(item => (
                 <div key={item.id} className="bg-white p-3 rounded-lg border border-gray-200 shadow-sm flex flex-col gap-2 animate-fade-in">
                    <div className="flex justify-between items-start">
                        <span className="font-bold text-gray-800 max-w-[150px] truncate">{item.name}</span>
                        <div className="flex items-center gap-2">
                            <span className="font-bold text-gray-900">{formatCurrency(item.price * item.quantity)}</span>
                            <button onClick={() => removeFromCart(item.id)} className="text-gray-400 hover:text-red-500 transition p-0.5 rounded-md hover:bg-red-50" title="Retirer l'article">
                                <X size={16} />
                            </button>
                        </div>
                    </div>
                    <div className="flex justify-between items-center">
                        <span className="text-xs text-gray-400">{item.dosage}</span>
                        <div className="flex items-center bg-gray-100 rounded-lg p-1">
                            <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:bg-white rounded shadow-sm transition"><Minus size={14}/></button>
                            <span className="w-8 text-center font-bold text-sm">{item.quantity}</span>
                            <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:bg-white rounded shadow-sm transition"><Plus size={14}/></button>
                        </div>
                    </div>
                 </div>
               ))
             )}
          </div>

          <div className="bg-white border-t border-gray-200 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]">

             {cart.length >= 2 && (
               <div className="px-4 py-2 bg-indigo-50 border-b border-indigo-100 flex justify-between items-center">
                  <span className="text-xs text-indigo-700 font-medium">Sécurité Médicament</span>
                  <button 
                    onClick={checkInteractions}
                    disabled={isChecking}
                    className="text-xs bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full hover:bg-indigo-200 transition flex items-center gap-1"
                  >
                    {isChecking ? <Loader2 size={12} className="animate-spin"/> : <AlertOctagon size={12}/>} Vérifier (IA)
                  </button>
               </div>
             )}
             {interactionAlert && (
                 <div className="px-4 py-2 bg-yellow-50 text-xs text-yellow-800 border-b border-yellow-200 max-h-24 overflow-y-auto">
                     {interactionAlert}
                 </div>
             )}

             <div className="p-4 space-y-4">
                 <div className="space-y-2">
                     <div className="flex justify-between text-gray-500 text-sm">
                         <span>Sous-total</span>
                         <span>{formatCurrency(totalAmount)}</span>
                     </div>

                     <div className="flex items-center justify-between">
                         <button 
                            onClick={() => setShowInsurance(!showInsurance)}
                            className={`text-xs flex items-center gap-1 font-bold ${showInsurance ? 'text-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}
                         >
                            <ShieldCheck size={14} /> {selectedInsuranceId ? 'Assurance Active' : 'Ajouter Assurance'} {showInsurance ? <ChevronUp size={12}/> : <ChevronDown size={12}/>}
                         </button>
                         {selectedInsuranceId && (
                             <span className="text-sm text-indigo-600 font-medium">-{formatCurrency(insuranceAmount)}</span>
                         )}
                     </div>

                     {showInsurance && (
