      const savedSale = await apiService.createSale(sale);
      setSales(prev => [...prev, savedSale]);
      const updatedDrugs = await apiService.getDrugs();
      setDrugs(updatedDrugs);
    } catch (error) {
      alert("Erreur lors de l'enregistrement de la vente.");
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setShowNotifications(false);
    setDismissedNotifications([]);
    setAiSelectedItems([]);
  };

  // Improved QuickAdd: Store item globally and redirect
  const handleQuickAddFromAI = (drug: Drug) => {
    setAiSelectedItems(prev => [...prev, drug]);
    // Notification visuelle légère ou redirection
    setCurrentView(ViewState.POS);
  };

  if (!currentUser) {
    return <Login users={users} onLogin={setCurrentUser} />;
  }

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="h-full flex flex-col items-center justify-center text-pharmacy-600">
          <Loader2 className="animate-spin mb-4" size={48} />
          <p className="font-medium">Synchronisation avec Laravel...</p>
        </div>
      );
    }

    switch (currentView) {
      case ViewState.DASHBOARD:
        return currentUser.role === 'ADMIN' ? <Dashboard drugs={drugs} sales={sales} /> : null;
      case ViewState.INVENTORY:
        return ['ADMIN', 'AGENT', 'SELLER'].includes(currentUser.role) ? <Inventory drugs={drugs} setDrugs={setDrugs} currentUser={currentUser} /> : null;
      case ViewState.POS:
        return ['ADMIN', 'CASHIER', 'SELLER'].includes(currentUser.role) ? 
          <POS 
            drugs={drugs} 
            setDrugs={setDrugs} 
            insurances={insurances} 
            onSaleComplete={handleSaleComplete} 
            currentUser={currentUser}
            pendingOrders={pendingOrders}
            setPendingOrders={setPendingOrders}
            aiIncomingItems={aiSelectedItems}
            onClearIncomingAI={() => setAiSelectedItems([])}
          /> : null;
      case ViewState.SALES_HISTORY:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <SalesHistory sales={sales} /> : null;
      case ViewState.SUPPLIERS:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <Suppliers suppliers={suppliers} setSuppliers={setSuppliers} /> : null;
      case ViewState.INSURANCES:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <Insurances insurances={insurances} setInsurances={setInsurances} /> : null;
      case ViewState.ASSISTANT:
        return ['ADMIN', 'AGENT', 'SELLER'].includes(currentUser.role) ? 
          <AIAssistant 
            drugs={drugs} 
            sales={sales} 
            suppliers={suppliers} 
            insurances={insurances} 
            onAddToCart={handleQuickAddFromAI}
          /> : null;
      case ViewState.SCANNER:
        return ['ADMIN', 'AGENT', 'SELLER'].includes(currentUser.role) ? <PrescriptionScanner /> : null;
      case ViewState.USERS:
        return currentUser.role === 'ADMIN' ? <UserManagement users={users} setUsers={setUsers} /> : null;
      case ViewState.EXPORTS:
        return currentUser.role === 'ADMIN' ? <DataExport drugs={drugs} sales={sales} users={users} suppliers={suppliers} insurances={insurances} /> : null;
      case ViewState.ORDERS:
        return ['ADMIN', 'AGENT'].includes(currentUser.role) ? <Orders drugs={drugs} suppliers={suppliers} /> : null;
      default:
        return <div>Accès non autorisé</div>;
    }
  };

  const NavItem = ({ view, icon: Icon, label, allowedRoles, isSubItem = false }: { view: ViewState, icon: any, label: string, allowedRoles: UserRole[], isSubItem?: boolean }) => {
    if (!allowedRoles.includes(currentUser.role)) return null;
    return (
      <button
        onClick={() => setCurrentView(view)}
        className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all duration-200 mb-1 ${
          currentView === view 
          ? 'bg-pharmacy-600 text-white shadow-md shadow-pharmacy-200' 
          : 'text-gray-600 hover:bg-pharmacy-50 hover:text-pharmacy-700'
        } ${isSubItem ? 'pl-11 text-sm' : ''}`}
      >
        <div className="relative">
          <Icon size={isSubItem ? 18 : 20} className={currentView === view ? 'text-white' : isSubItem ? 'text-gray-400' : 'text-gray-500'} />
          {view === ViewState.POS && aiSelectedItems.length > 0 && (
             <span className="absolute -top-1 -right-1 flex h-3 w-3">
               <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
               <span className="relative inline-flex rounded-full h-3 w-3 bg-red-500"></span>
             </span>
          )}
        </div>
        <span className="font-medium">{label}</span>
      </button>
    );
  };

  const NavGroup = ({ label, icon: Icon, children, allowedRoles }: { label: string, icon: any, children?: React.ReactNode, allowedRoles: UserRole[] }) => {
    const [isOpen, setIsOpen] = useState(false);
    if (!allowedRoles.includes(currentUser.role)) return null;
    return (
      <div className="mb-2">
        <button onClick={() => setIsOpen(!isOpen)} className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-colors duration-200 hover:bg-gray-50 ${isOpen ? 'text-pharmacy-800 bg-gray-50' : 'text-gray-700'}`}>
          <div className="flex items-center space-x-3">
             <Icon size={20} className="text-gray-500" />
             <span className="font-bold text-sm uppercase tracking-wide">{label}</span>
          </div>
          {isOpen ? <ChevronDown size={16} /> : <ChevronRight size={16} />}
        </button>
        <div className={`overflow-hidden transition-all duration-300 ease-in-out ${isOpen ? 'max-h-96 opacity-100 mt-1' : 'max-h-0 opacity-0'}`}>
           {children}
        </div>
      </div>
    );
  };

  return (
    <div className="flex h-screen bg-gray-100 font-sans overflow-hidden">
      {showCashClosing && <CashClosing sales={sales} currentUser={currentUser} onClose={() => setShowCashClosing(false)} />}
      <aside className="w-64 bg-white border-r border-gray-200 flex flex-col shadow-sm z-10">
        <div className="p-6 flex items-center space-x-3 border-b border-gray-100">
          <div className="bg-pharmacy-600 p-2 rounded-lg text-white"><Activity size={24} /></div>
          <div>
            <h1 className="text-xl font-bold text-gray-800 tracking-tight">Fasopharm</h1>
            <p className="text-xs text-gray-400 font-medium">{currentUser.role}</p>
          </div>
        </div>
        <nav className="flex-1 p-3 space-y-1 overflow-y-auto custom-scrollbar">
          <NavItem view={ViewState.DASHBOARD} icon={LayoutDashboard} label="Tableau de Bord" allowedRoles={['ADMIN']} />
          <NavItem view={ViewState.POS} icon={ShoppingCart} label={currentUser.role === 'SELLER' ? "Préparation" : "Caisse"} allowedRoles={['ADMIN', 'CASHIER', 'SELLER']} />
          <NavGroup label="Logistique" icon={Truck} allowedRoles={['ADMIN', 'AGENT', 'SELLER']}>
             <NavItem view={ViewState.INVENTORY} icon={Package} label="Stocks" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} isSubItem />
             <NavItem view={ViewState.ORDERS} icon={ShoppingBag} label="Réappro" allowedRoles={['ADMIN', 'AGENT']} isSubItem />
             <NavItem view={ViewState.SUPPLIERS} icon={Layers} label="Fournisseurs" allowedRoles={['ADMIN', 'AGENT']} isSubItem />
          </NavGroup>
          <NavGroup label="Gestion" icon={FileText} allowedRoles={['ADMIN', 'AGENT']}>
             <NavItem view={ViewState.SALES_HISTORY} icon={History} label="Historique" allowedRoles={['ADMIN', 'AGENT']} isSubItem />
             <NavItem view={ViewState.INSURANCES} icon={ShieldCheck} label="Assurances" allowedRoles={['ADMIN', 'AGENT']} isSubItem />
             <NavItem view={ViewState.EXPORTS} icon={Database} label="Exports" allowedRoles={['ADMIN']} isSubItem />
             <NavItem view={ViewState.USERS} icon={Users} label="Utilisateurs" allowedRoles={['ADMIN']} isSubItem />
          </NavGroup>
          <NavGroup label="IA" icon={BrainCircuit} allowedRoles={['ADMIN', 'AGENT', 'SELLER']}>
             <NavItem view={ViewState.ASSISTANT} icon={Bot} label="Assistant" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} isSubItem />
             <NavItem view={ViewState.SCANNER} icon={ScanLine} label="Scan" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} isSubItem />
          </NavGroup>
        </nav>
        <div className="p-4 border-t border-gray-100">
          <button onClick={handleLogout} className="w-full flex items-center justify-center space-x-2 p-2 text-red-600 hover:bg-red-50 rounded-lg transition">
            <LogOut size={18} /><span className="text-sm font-medium">Déconnexion</span>
          </button>
        </div>
      </aside>
      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-16 bg-white border-b border-gray-200 flex items-center justify-between px-6 shadow-sm">
          <h2 className="text-xl font-bold text-gray-800">{currentView}</h2>
          <div className="flex items-center space-x-4">
             {['ADMIN', 'CASHIER'].includes(currentUser.role) && (
               <button onClick={() => setShowCashClosing(true)} className="flex items-center gap-2 px-3 py-1.5 bg-pharmacy-100 text-pharmacy-700 rounded-lg text-sm font-bold hover:bg-pharmacy-200 transition">
                   <Wallet size={16} /><span>Caisse</span>
               </button>
             )}
            <div className="relative">
              <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 text-gray-500 hover:bg-gray-100 rounded-full relative">
                <Bell size={20} />
                {totalNotifications > 0 && <span className="absolute top-0 right-0 h-4 w-4 bg-red-500 rounded-full border-2 border-white flex items-center justify-center text-[10px] text-white font-bold">{totalNotifications}</span>}
              </button>
            </div>
          </div>
        </header>
        <div className="flex-1 overflow-hidden relative">{renderContent()}</div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Message, Drug, Sale, Supplier, Insurance, ViewState } from '../types';
import { getChatResponse } from '../services/geminiService';
import { Send, Bot, User, Sparkles, Database, Stethoscope, PlusCircle, AlertCircle, Check, X, Wand2 } from 'lucide-react';

interface AIAssistantProps {
  drugs: Drug[];
  sales: Sale[];
  suppliers: Supplier[];
  insurances: Insurance[];
  currentView?: ViewState;
  onAddToCart?: (drug: Drug) => void;
  isSidebar?: boolean;
  onClose?: () => void;
}

const AIAssistant: React.FC<AIAssistantProps> = ({ 
  drugs, sales, suppliers, insurances, currentView, onAddToCart, isSidebar, onClose 
}) => {
  const [messages, setMessages] = useState<Message[]>([
    { id: '0', role: 'model', text: 'Bonjour ! Je suis votre copilote Fasopharm. Je peux vous aider à gérer vos stocks, analyser vos ventes ou préparer une ordonnance. Que souhaitez-vous faire ?', timestamp: new Date() }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [addedIds, setAddedIds] = useState<string[]>([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(scrollToBottom, [messages]);

  const handleSend = async (e?: React.FormEvent, customPrompt?: string) => {
    e?.preventDefault();
    const textToSend = customPrompt || input;
    if (!textToSend.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    const history = messages.map(m => m.text);
    const contextData = JSON.stringify({
      view: currentView,
      inventaire_disponible: drugs.slice(0, 50).map(d => ({ id: d.id, nom: d.name, stock: d.stock, prix: d.price })),
      ventes_recentes: sales.slice(-10).map(s => ({ total: s.total, date: s.timestamp })),
      mission_specifique: "Fournir des conseils basés sur la vue actuelle : " + currentView
    });

    const responseText = await getChatResponse(history, textToSend, contextData);

    const botMsg: Message = {
      id: (Date.now() + 1).toString(),
      role: 'model',
      text: responseText,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, botMsg]);
    setIsLoading(false);
  };

  const handleQuickInsight = () => {
    let prompt = "";
    switch(currentView) {
      case ViewState.INVENTORY: prompt = "Analyse mon inventaire actuel et dis-moi quels produits je devrais commander en priorité et pourquoi."; break;
      case ViewState.DASHBOARD: prompt = "Fais-moi un résumé de ma performance financière de la semaine et suggère une amélioration."; break;
      case ViewState.POS: prompt = "Donne-moi des conseils pour améliorer l'expérience client au comptoir aujourd'hui."; break;
      default: prompt = "Quelles sont les tâches prioritaires aujourd'hui ?";
    }
    handleSend(undefined, prompt);
  };

  const renderMessageContent = (text: string) => {
    const foundDrugs = drugs.filter(d => text.toLowerCase().includes(d.name.toLowerCase()));
    return (
      <div className="space-y-3">
        <p className="leading-relaxed whitespace-pre-wrap">{text}</p>
        {foundDrugs.length > 0 && onAddToCart && (
          <div className="mt-4 pt-3 border-t border-gray-100 flex flex-wrap gap-2">
            {foundDrugs.map(drug => (
              <button 
                key={drug.id}
                onClick={() => { onAddToCart(drug); setAddedIds(prev => [...prev, drug.id]); }}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border text-xs font-bold transition ${
                  addedIds.includes(drug.id) ? 'bg-green-50 border-green-200 text-green-700' : 'bg-pharmacy-50 border-pharmacy-200 text-pharmacy-700 hover:bg-pharmacy-100'
                }`}
              >
                {addedIds.includes(drug.id) ? <Check size={12} /> : <PlusCircle size={12} />}
                {drug.name}
              </button>
            ))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className={`flex flex-col h-full bg-white ${isSidebar ? 'border-l' : 'rounded-2xl border m-4 shadow-sm'} border-gray-100 overflow-hidden`}>
      <div className="p-4 bg-gradient-to-r from-pharmacy-800 to-indigo-700 text-white flex items-center justify-between shadow-md">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-white/20 rounded-lg animate-pulse">
            <Sparkles size={20} />
          </div>
          <div>
            <h2 className="font-bold">IA Fasopharm</h2>
            <p className="text-[10px] opacity-70 uppercase tracking-widest">Co-pilote intelligent</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={handleQuickInsight} className="p-2 hover:bg-white/10 rounded-lg transition" title="Auto-Analyse">
             <Wand2 size={18} />
          </button>
          {onClose && <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-lg transition"><X size={20} /></button>}
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50 custom-scrollbar">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[90%] p-3 rounded-2xl text-sm shadow-sm ${
              msg.role === 'user' ? 'bg-pharmacy-700 text-white rounded-tr-none' : 'bg-white text-gray-800 border border-gray-100 rounded-tl-none'
            }`}>
              {msg.role === 'model' ? renderMessageContent(msg.text) : msg.text}
              <p className={`text-[10px] mt-1 opacity-40 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                {new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
              </p>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="p-4 bg-white border border-gray-100 rounded-2xl rounded-tl-none shadow-sm flex gap-2">
              <div className="w-1.5 h-1.5 bg-pharmacy-400 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-pharmacy-400 rounded-full animate-bounce delay-75"></div>
              <div className="w-1.5 h-1.5 bg-pharmacy-400 rounded-full animate-bounce delay-150"></div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-white border-t border-gray-100">
        <form onSubmit={handleSend} className="flex gap-2">
          <input
            type="text"
            className="flex-1 border border-gray-200 rounded-xl px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-pharmacy-500 bg-gray-50"
            placeholder="Posez une question contextuelle..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
          />
          <button type="submit" disabled={isLoading || !input.trim()} className="bg-pharmacy-600 text-white p-2 rounded-xl hover:bg-pharmacy-700 disabled:opacity-50 transition">
            <Send size={18} />
          </button>
        </form>
      </div>
    </div>
  );
};

export default AIAssistant;

import React, { useState, useEffect } from 'react';
import { ViewState, Drug, Sale, User, UserRole, Supplier, Insurance, PendingOrder } from './types';
import { INITIAL_DRUGS, INITIAL_USERS, INITIAL_SUPPLIERS, INITIAL_INSURANCES } from './constants';
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import POS from './components/POS';
import AIAssistant from './components/AIAssistant';
import PrescriptionScanner from './components/PrescriptionScanner';
import Login from './components/Login';
import UserManagement from './components/UserManagement';
import SalesHistory from './components/SalesHistory';
import Suppliers from './components/Suppliers';
import Insurances from './components/Insurances';
import DataExport from './components/DataExport';
import Orders from './components/Orders';
import CashClosing from './components/CashClosing';
import { apiService } from './services/apiService';

import { 
  LayoutDashboard, Package, ShoppingCart, Bot, ScanLine, Activity, LogOut, Users, Bell, 
  AlertTriangle, Clock, History, Truck, ShieldCheck, Database, ShoppingBag, Wallet,
  ChevronDown, ChevronRight, Layers, FileText, BrainCircuit, Loader2, Sparkles
} from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const [drugs, setDrugs] = useState<Drug[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [insurances, setInsurances] = useState<Insurance[]>([]);
  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>([]);
  const [aiIncomingItems, setAiIncomingItems] = useState<Drug[]>([]);

  const [isLoading, setIsLoading] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [showCashClosing, setShowCashClosing] = useState(false);
  const [showAISidebar, setShowAISidebar] = useState(false);
  const [dismissedNotifications, setDismissedNotifications] = useState<string[]>([]);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const [drugsData, salesData, suppliersData, insurancesData] = await Promise.all([
        apiService.getDrugs().catch(() => INITIAL_DRUGS),
        apiService.getSales().catch(() => []),
        apiService.getSuppliers().catch(() => INITIAL_SUPPLIERS),
        apiService.getInsurances().catch(() => INITIAL_INSURANCES)
      ]);
      setDrugs(drugsData);
      setSales(salesData);
      setSuppliers(suppliersData);
      setInsurances(insurancesData);
    } catch (error) { console.error(error); }
    finally { setIsLoading(false); }
  };

  useEffect(() => { if (currentUser) loadData(); }, [currentUser]);

  const lowStockItems = drugs.filter(d => d.stock < 20 && !dismissedNotifications.includes(`stock-${d.id}`));
  const expiringItems = drugs.filter(d => {
    if (!d.expiryDate) return false;
    const today = new Date();
    const exp = new Date(d.expiryDate);
    return Math.ceil((exp.getTime() - today.getTime()) / (1000 * 60 * 60 * 24)) <= 90;
  });
  const totalNotifications = lowStockItems.length + expiringItems.length;

  const handleSaleComplete = async (sale: Sale) => {
    try {
      await apiService.createSale(sale);
      loadData();
    } catch (error) { alert("Erreur de vente."); }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setShowAISidebar(false);
  };

  const handleQuickAddFromAI = (drug: Drug) => {
    setAiIncomingItems(prev => [...prev, drug]);
    setCurrentView(ViewState.POS);
  };

  if (!currentUser) return <Login users={users} onLogin={setCurrentUser} />;

  const renderContent = () => {
    if (isLoading) return <div className="h-full flex items-center justify-center"><Loader2 className="animate-spin text-pharmacy-600" size={48} /></div>;

    const commonProps = { drugs, sales, suppliers, insurances, currentUser };

    switch (currentView) {
      case ViewState.DASHBOARD: return <Dashboard drugs={drugs} sales={sales} />;
      case ViewState.INVENTORY: return <Inventory drugs={drugs} setDrugs={setDrugs} currentUser={currentUser} />;
      case ViewState.POS: return (
        <POS 
          {...commonProps} 
          setDrugs={setDrugs} 
          onSaleComplete={handleSaleComplete} 
          pendingOrders={pendingOrders} 
          setPendingOrders={setPendingOrders}
          aiIncomingItems={aiIncomingItems}
          onClearIncomingAI={() => setAiIncomingItems([])}
        />
      );
      case ViewState.ASSISTANT: return <AIAssistant {...commonProps} onAddToCart={handleQuickAddFromAI} />;
      case ViewState.SCANNER: return <PrescriptionScanner />;
      case ViewState.SALES_HISTORY: return <SalesHistory sales={sales} />;
      case ViewState.SUPPLIERS: return <Suppliers suppliers={suppliers} setSuppliers={setSuppliers} />;
      case ViewState.INSURANCES: return <Insurances insurances={insurances} setInsurances={setInsurances} />;
      case ViewState.USERS: return <UserManagement users={users} setUsers={setUsers} />;
      case ViewState.EXPORTS: return <DataExport {...commonProps} users={users} />;
      case ViewState.ORDERS: return <Orders drugs={drugs} suppliers={suppliers} />;
      default: return null;
    }
  };

  return (
    <div className="flex h-screen bg-gray-100 font-sans overflow-hidden">
      {showCashClosing && <CashClosing sales={sales} currentUser={currentUser} onClose={() => setShowCashClosing(false)} />}

      <aside className="w-64 bg-white border-r border-gray-200 flex flex-col shadow-sm z-10">
        <div className="p-6 flex items-center space-x-3 border-b border-gray-100">
          <div className="bg-pharmacy-600 p-2 rounded-lg text-white"><Activity size={24} /></div>
          <div>
            <h1 className="text-xl font-bold text-gray-800 tracking-tight">Fasopharm</h1>
            <p className="text-[10px] text-gray-400 font-bold uppercase">{currentUser.role}</p>
          </div>
        </div>
        <nav className="flex-1 p-3 space-y-1 overflow-y-auto">
          <NavItem view={ViewState.DASHBOARD} icon={LayoutDashboard} label="Tableau de Bord" allowedRoles={['ADMIN']} setCurrentView={setCurrentView} currentView={currentView} currentUser={currentUser} />
          <NavItem view={ViewState.POS} icon={ShoppingCart} label="Vente & Caisse" allowedRoles={['ADMIN', 'CASHIER', 'SELLER']} setCurrentView={setCurrentView} currentView={currentView} currentUser={currentUser} aiBadge={aiIncomingItems.length > 0} />
          <NavItem view={ViewState.INVENTORY} icon={Package} label="Stocks" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} setCurrentView={setCurrentView} currentView={currentView} currentUser={currentUser} />
          <NavItem view={ViewState.ORDERS} icon={ShoppingBag} label="Réappro" allowedRoles={['ADMIN', 'AGENT']} setCurrentView={setCurrentView} currentView={currentView} currentUser={currentUser} />
          <NavItem view={ViewState.ASSISTANT} icon={BrainCircuit} label="Assistant IA" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} setCurrentView={setCurrentView} currentView={currentView} currentUser={currentUser} />

          <div className="mt-8 px-4 py-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">Rapports</div>
          <NavItem view={ViewState.SALES_HISTORY} icon={History} label="Historique" allowedRoles={['ADMIN', 'AGENT']} setCurrentView={setCurrentView} currentView={currentView} currentUser={currentUser} />
          <NavItem view={ViewState.EXPORTS} icon={Database} label="Données" allowedRoles={['ADMIN']} setCurrentView={setCurrentView} currentView={currentView} currentUser={currentUser} />
        </nav>
        <div className="p-4 border-t">
          <button onClick={handleLogout} className="w-full flex items-center justify-center gap-2 p-2 text-red-600 hover:bg-red-50 rounded-lg transition text-sm font-bold">
            <LogOut size={18} /> Déconnexion
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-16 bg-white border-b flex items-center justify-between px-6 shadow-sm z-20">
          <div className="flex items-center gap-4">
             <h2 className="text-xl font-black text-gray-800 tracking-tight">{currentView}</h2>
             <button 
                onClick={() => setShowAISidebar(!showAISidebar)}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-bold transition-all ${showAISidebar ? 'bg-indigo-600 text-white shadow-indigo-200' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'} shadow-md`}
             >
                <Sparkles size={14} /> {showAISidebar ? 'Masquer Copilote' : 'Activer Copilote IA'}
             </button>
          </div>
          <div className="flex items-center space-x-4">
             <button onClick={() => setShowCashClosing(true)} className="p-2 bg-gray-100 text-gray-600 rounded-full hover:bg-gray-200 transition"><Wallet size={20} /></button>
             <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 text-gray-500 hover:bg-gray-100 rounded-full relative">
                <Bell size={20} />
                {totalNotifications > 0 && <span className="absolute top-0 right-0 h-4 w-4 bg-red-500 rounded-full border-2 border-white text-[10px] text-white flex items-center justify-center font-bold">{totalNotifications}</span>}
             </button>
          </div>
        </header>
        <div className="flex-1 flex overflow-hidden">
           <div className="flex-1 overflow-auto bg-gray-50">{renderContent()}</div>
           {showAISidebar && (
             <div className="w-96 animate-slide-in-right">
                <AIAssistant 
                  drugs={drugs} 
                  sales={sales} 
                  suppliers={suppliers} 
                  insurances={insurances} 
                  currentView={currentView}
                  onAddToCart={handleQuickAddFromAI}
                  isSidebar={true}
                  onClose={() => setShowAISidebar(false)}
                />
             </div>
           )}
        </div>
      </main>
    </div>
  );
};

const NavItem = ({ view, icon: Icon, label, allowedRoles, setCurrentView, currentView, currentUser, aiBadge }: any) => {
  if (!allowedRoles.includes(currentUser.role)) return null;
  const isActive = currentView === view;
  return (
    <button
      onClick={() => setCurrentView(view)}
      className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all duration-200 ${
        isActive ? 'bg-pharmacy-600 text-white shadow-lg' : 'text-gray-600 hover:bg-pharmacy-50'
      }`}
    >
      <div className="relative">
        <Icon size={20} />
        {aiBadge && <span className="absolute -top-1 -right-1 h-2 w-2 bg-red-500 rounded-full"></span>}
      </div>
      <span className="font-bold text-sm">{label}</span>
    </button>
  );
};

export default App;

import React, { useState } from 'react';
import { Drug, User } from '../types';
import { Plus, Search, Trash2, Edit2, Package, Calendar, ScanLine, Loader2, Camera, Lock, Sparkles, Wand2 } from 'lucide-react';
import { analyzeMedicineBox } from '../services/geminiService';
import { apiService } from '../services/apiService';

interface InventoryProps {
  drugs: Drug[];
  setDrugs: React.Dispatch<React.SetStateAction<Drug[]>>;
  currentUser: User;
}

const Inventory: React.FC<InventoryProps> = ({ drugs, setDrugs, currentUser }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingDrug, setEditingDrug] = useState<Drug | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const canAdd = currentUser.role === 'ADMIN' || currentUser.role === 'AGENT';
  const canEdit = currentUser.role === 'ADMIN';

  const [formData, setFormData] = useState<Partial<Drug>>({
    name: '', description: '', category: '', dosage: '', price: 0, stock: 0, expiryDate: ''
  });

  const handleOpenModal = (drug?: Drug) => {
    if (drug) { setEditingDrug(drug); setFormData(drug); }
    else { setEditingDrug(null); setFormData({ name: '', description: '', category: '', dosage: '', price: 0, stock: 0, expiryDate: '' }); }
    setIsModalOpen(true);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      const savedDrug = await apiService.saveDrug(formData);
      if (editingDrug) setDrugs(drugs.map(d => d.id === editingDrug.id ? savedDrug : d));
      else setDrugs([...drugs, savedDrug]);
      setIsModalOpen(false);
    } catch (error) { alert("Erreur serveur."); }
    finally { setIsSaving(false); }
  };

  const handleScanProduct = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setIsScanning(true);
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = reader.result as string;
        const result = await analyzeMedicineBox(base64String);
        if (result) setFormData(prev => ({ ...prev, ...result }));
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const filteredDrugs = drugs.filter(d => 
    d.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    d.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="p-6 h-full flex flex-col space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-black text-gray-800">Inventaire Global</h2>
          <p className="text-xs text-gray-400 font-bold uppercase tracking-tighter">Synchronisé avec le serveur central</p>
        </div>
        <div className="flex gap-2">
          <button className="flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-700 rounded-xl border border-indigo-100 font-bold text-sm hover:bg-indigo-100 transition shadow-sm group">
            <Sparkles size={16} className="group-hover:animate-pulse" /> IA Auto-Recharge
          </button>
          {canAdd && (
            <button onClick={() => handleOpenModal()} className="bg-pharmacy-600 hover:bg-pharmacy-700 text-white px-4 py-2 rounded-xl flex items-center gap-2 transition shadow-lg font-bold">
              <Plus size={20} /> Nouveau
            </button>
          )}
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 flex-1 flex flex-col overflow-hidden">
        <div className="p-4 border-b border-gray-50 bg-gray-50/50 flex gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input type="text" placeholder="Rechercher un médicament..." className="w-full pl-10 pr-4 py-2.5 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none shadow-sm" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
          <label className="flex items-center gap-2 px-4 py-2.5 bg-white border border-gray-200 rounded-xl cursor-pointer hover:bg-gray-50 transition shadow-sm font-bold text-sm text-gray-600">
             {isScanning ? <Loader2 className="animate-spin" size={18} /> : <Camera size={18} />}
             <span>Scan IA</span>
             <input type="file" accept="image/*" className="hidden" onChange={handleScanProduct} disabled={isScanning} />
          </label>
        </div>

        <div className="overflow-auto flex-1">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50 sticky top-0">
              <tr>
                <th className="px-6 py-4 text-left text-[10px] font-black text-gray-400 uppercase tracking-widest">Produit</th>
                <th className="px-6 py-4 text-left text-[10px] font-black text-gray-400 uppercase tracking-widest">Catégorie</th>
                <th className="px-6 py-4 text-right text-[10px] font-black text-gray-400 uppercase tracking-widest">Prix Vente</th>
                <th className="px-6 py-4 text-right text-[10px] font-black text-gray-400 uppercase tracking-widest">Stock</th>
                <th className="px-6 py-4 text-right text-[10px] font-black text-gray-400 uppercase tracking-widest">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-100">
              {filteredDrugs.map(drug => (
                <tr key={drug.id} className="hover:bg-pharmacy-50/30 transition group">
                  <td className="px-6 py-4">
                    <div className="text-sm font-bold text-gray-800">{drug.name}</div>
                    <div className="text-[10px] text-gray-400 font-medium">{drug.dosage}</div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="px-2.5 py-1 bg-blue-50 text-blue-700 rounded-lg text-[10px] font-black uppercase tracking-tight">{drug.category}</span>
                  </td>
                  <td className="px-6 py-4 text-right text-sm font-bold text-gray-600">
                    {drug.price.toLocaleString()} F
                  </td>
                  <td className={`px-6 py-4 text-right`}>
                    <span className={`px-3 py-1 rounded-full text-xs font-black ${drug.stock < 20 ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-700'}`}>
                        {drug.stock}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-1 opacity-0 group-hover:opacity-100 transition">
                      <button onClick={() => handleOpenModal(drug)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg"><Edit2 size={16} /></button>
                      <button className="p-2 text-red-600 hover:bg-red-50 rounded-lg"><Trash2 size={16} /></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-6 max-h-[90vh] overflow-y-auto">
            <h3 className="text-xl font-black mb-6 flex items-center gap-2">
                <Wand2 size={24} className="text-pharmacy-600" />
                {editingDrug ? 'Modifier' : 'Nouveau'} Médicament
            </h3>
            <form onSubmit={handleSave} className="space-y-4">
              <div>
                <label className="text-[10px] font-black text-gray-400 uppercase block mb-1">Nom du produit</label>
                <input required type="text" className="w-full border-gray-200 border p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[10px] font-black text-gray-400 uppercase block mb-1">Prix Vente (F)</label>
                  <input required type="number" className="w-full border-gray-200 border p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none font-bold" value={formData.price} onChange={e => setFormData({...formData, price: parseFloat(e.target.value)})} />
                </div>
                <div>
                  <label className="text-[10px] font-black text-gray-400 uppercase block mb-1">Stock Initial</label>
                  <input required type="number" className="w-full border-gray-200 border p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none font-bold" value={formData.stock} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} />
                </div>
              </div>
              <div>
                <label className="text-[10px] font-black text-gray-400 uppercase block mb-1">Date d'expiration</label>
                <input required type="date" className="w-full border-gray-200 border p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none" value={formData.expiryDate} onChange={e => setFormData({...formData, expiryDate: e.target.value})} />
              </div>
              <div className="flex gap-2 pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-3 bg-gray-100 text-gray-600 rounded-xl font-bold hover:bg-gray-200 transition">Annuler</button>
                <button type="submit" disabled={isSaving} className="flex-[2] py-3 bg-pharmacy-600 text-white rounded-xl font-bold hover:bg-pharmacy-700 transition shadow-lg flex justify-center items-center gap-2">
                  {isSaving && <Loader2 className="animate-spin" size={18} />}
                  Enregistrer
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;

import React, { useState, useEffect } from 'react';
import { ViewState, Drug, Sale, User, UserRole, Supplier, Insurance, PendingOrder } from './types';
import { INITIAL_DRUGS, INITIAL_USERS, INITIAL_SUPPLIERS, INITIAL_INSURANCES } from './constants';
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import POS from './components/POS';
import AIAssistant from './components/AIAssistant';
import PrescriptionScanner from './components/PrescriptionScanner';
import Login from './components/Login';
import UserManagement from './components/UserManagement';
import SalesHistory from './components/SalesHistory';
import Suppliers from './components/Suppliers';
import Insurances from './components/Insurances';
import DataExport from './components/DataExport';
import Orders from './components/Orders';
import CashClosing from './components/CashClosing';
import { apiService } from './services/apiService';

import { 
  LayoutDashboard, Package, ShoppingCart, Bot, ScanLine, Activity, LogOut, Users, Bell, 
  AlertTriangle, Clock, History, Truck, ShieldCheck, Database, ShoppingBag, Wallet,
  ChevronDown, ChevronRight, Layers, FileText, BrainCircuit, Loader2, Sparkles
} from 'lucide-react';

const App: React.FC = () => {
  // Global State
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  // App Data
  const [drugs, setDrugs] = useState<Drug[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [insurances, setInsurances] = useState<Insurance[]>([]);
  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>([]);

  // New State for AI Bridge & UI
  const [aiSelectedItems, setAiSelectedItems] = useState<Drug[]>([]);
  const [showAISidebar, setShowAISidebar] = useState(false);

  const [isLoading, setIsLoading] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [showCashClosing, setShowCashClosing] = useState(false);
  const [dismissedNotifications, setDismissedNotifications] = useState<string[]>([]);

  // Fetch data
  const loadData = async () => {
    setIsLoading(true);
    try {
      const [drugsData, salesData, suppliersData, insurancesData] = await Promise.all([
        apiService.getDrugs().catch(() => INITIAL_DRUGS),
        apiService.getSales().catch(() => []),
        apiService.getSuppliers().catch(() => INITIAL_SUPPLIERS),
        apiService.getInsurances().catch(() => INITIAL_INSURANCES)
      ]);
      setDrugs(drugsData);
      setSales(salesData);
      setSuppliers(suppliersData);
      setInsurances(insurancesData);
    } catch (error) {
      console.error("Failed to load data", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (currentUser) {
      loadData();
    }
  }, [currentUser]);

  // Notifications logic
  const lowStockItems = drugs.filter(d => d.stock < 20 && !dismissedNotifications.includes(`stock-${d.id}`));
  const expiringItems = drugs.filter(d => {
    if (!d.expiryDate) return false;
    const today = new Date();
    const exp = new Date(d.expiryDate);
    const diffDays = Math.ceil((exp.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    return diffDays <= 90;
  });
  const totalNotifications = lowStockItems.length + expiringItems.length;

  useEffect(() => {
    if (currentUser) {
      if (currentUser.role === 'CASHIER') setCurrentView(ViewState.POS);
      else if (currentUser.role === 'AGENT') setCurrentView(ViewState.INVENTORY);
      else if (currentUser.role === 'SELLER') setCurrentView(ViewState.POS);
      else setCurrentView(ViewState.DASHBOARD);
    }
  }, [currentUser]);

  const handleSaleComplete = async (sale: Sale) => {
    try {
      await apiService.createSale(sale);
      loadData();
    } catch (error) {
      alert("Erreur lors de l'enregistrement de la vente.");
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setShowAISidebar(false);
    setShowNotifications(false);
  };

  const handleQuickAddFromAI = (drug: Drug) => {
    setAiSelectedItems(prev => [...prev, drug]);
    setCurrentView(ViewState.POS);
  };

  if (!currentUser) {
    return <Login users={users} onLogin={setCurrentUser} />;
  }

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="h-full flex flex-col items-center justify-center text-pharmacy-600">
          <Loader2 className="animate-spin mb-4" size={48} />
          <p className="font-medium">Chargement des données...</p>
        </div>
      );
    }

    const assistant = (
      <AIAssistant 
        drugs={drugs} 
        sales={sales} 
        suppliers={suppliers} 
        insurances={insurances} 
        currentView={currentView}
        onAddToCart={handleQuickAddFromAI}
      />
    );

    switch (currentView) {
      case ViewState.DASHBOARD:
        return currentUser.role === 'ADMIN' ? <Dashboard drugs={drugs} sales={sales} /> : null;
      case ViewState.INVENTORY:
        return ['ADMIN', 'AGENT', 'SELLER'].includes(currentUser.role) ? <Inventory drugs={drugs} setDrugs={setDrugs} currentUser={currentUser} /> : null;
      case ViewState.POS:
        return ['ADMIN', 'CASHIER', 'SELLER'].includes(currentUser.role) ? 
          <POS 
            drugs={drugs} 
            setDrugs={setDrugs} 
            insurances={insurances} 
            onSaleComplete={handleSaleComplete} 
            currentUser={currentUser}
            pendingOrders={pendingOrders}
            setPendingOrders={setPendingOrders}
            aiIncomingItems={aiSelectedItems}
            onClearIncomingAI={() => setAiSelectedItems([])}
          /> : null;
      case ViewState.SALES_HISTORY:
        return <SalesHistory sales={sales} />;
      case ViewState.SUPPLIERS:
        return <Suppliers suppliers={suppliers} setSuppliers={setSuppliers} />;
      case ViewState.INSURANCES:
        return <Insurances insurances={insurances} setInsurances={setInsurances} />;
      case ViewState.ASSISTANT:
        return assistant;
      case ViewState.SCANNER:
        return <PrescriptionScanner />;
      case ViewState.USERS:
        return currentUser.role === 'ADMIN' ? <UserManagement users={users} setUsers={setUsers} /> : null;
      case ViewState.EXPORTS:
        return currentUser.role === 'ADMIN' ? <DataExport drugs={drugs} sales={sales} users={users} suppliers={suppliers} insurances={insurances} /> : null;
      case ViewState.ORDERS:
        return <Orders drugs={drugs} suppliers={suppliers} />;
      default:
        return null;
    }
  };

  return (
    <div className="flex h-screen bg-gray-100 font-sans overflow-hidden">
      {showCashClosing && <CashClosing sales={sales} currentUser={currentUser} onClose={() => setShowCashClosing(false)} />}

      <aside className="w-64 bg-white border-r border-gray-200 flex flex-col shadow-sm z-10">
        <div className="p-6 flex items-center space-x-3 border-b border-gray-100">
          <div className="bg-pharmacy-600 p-2 rounded-lg text-white shadow-md"><Activity size={24} /></div>
          <div>
            <h1 className="text-xl font-bold text-gray-800 tracking-tight">Fasopharm</h1>
            <p className="text-[10px] text-gray-400 font-bold uppercase">{currentUser.role}</p>
          </div>
        </div>

        <nav className="flex-1 p-3 space-y-1 overflow-y-auto custom-scrollbar">
          <NavItem view={ViewState.DASHBOARD} icon={LayoutDashboard} label="Tableau de Bord" allowedRoles={['ADMIN']} currentView={currentView} onClick={setCurrentView} currentUser={currentUser} />
          <NavItem view={ViewState.POS} icon={ShoppingCart} label="Caisse & Ventes" allowedRoles={['ADMIN', 'CASHIER', 'SELLER']} currentView={currentView} onClick={setCurrentView} currentUser={currentUser} hasIndicator={aiSelectedItems.length > 0} />
          <NavItem view={ViewState.INVENTORY} icon={Package} label="Stocks" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} currentView={currentView} onClick={setCurrentView} currentUser={currentUser} />
          <NavItem view={ViewState.ORDERS} icon={ShoppingBag} label="Réappro" allowedRoles={['ADMIN', 'AGENT']} currentView={currentView} onClick={setCurrentView} currentUser={currentUser} />
          <NavItem view={ViewState.SALES_HISTORY} icon={History} label="Historique" allowedRoles={['ADMIN', 'AGENT']} currentView={currentView} onClick={setCurrentView} currentUser={currentUser} />
          <NavItem view={ViewState.ASSISTANT} icon={BrainCircuit} label="Assistant IA" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} currentView={currentView} onClick={setCurrentView} currentUser={currentUser} />

          {currentUser.role === 'ADMIN' && (
            <div className="pt-4 mt-4 border-t border-gray-100">
              <NavItem view={ViewState.USERS} icon={Users} label="Utilisateurs" allowedRoles={['ADMIN']} currentView={currentView} onClick={setCurrentView} currentUser={currentUser} />
              <NavItem view={ViewState.EXPORTS} icon={Database} label="Exports" allowedRoles={['ADMIN']} currentView={currentView} onClick={setCurrentView} currentUser={currentUser} />
            </div>
          )}
        </nav>

        <div className="p-4 border-t border-gray-100">
          <button onClick={handleLogout} className="w-full flex items-center justify-center gap-2 p-2 text-red-600 hover:bg-red-50 rounded-lg transition text-sm font-bold">
            <LogOut size={18} /> Déconnexion
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-16 bg-white border-b border-gray-200 flex items-center justify-between px-6 shadow-sm z-20">
          <div className="flex items-center gap-4">
             <h2 className="text-xl font-bold text-gray-800">{currentView}</h2>
             <button 
                onClick={() => setShowAISidebar(!showAISidebar)}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-bold transition-all ${showAISidebar ? 'bg-indigo-600 text-white shadow-indigo-200' : 'bg-indigo-50 text-indigo-700 hover:bg-indigo-100'} shadow-md`}
             >
                <Sparkles size={14} className={showAISidebar ? 'animate-spin' : ''} />
                {showAISidebar ? 'Désactiver Copilote' : 'Copilote IA'}
             </button>
          </div>
          <div className="flex items-center space-x-4">
             {['ADMIN', 'CASHIER'].includes(currentUser.role) && (
               <button onClick={() => setShowCashClosing(true)} className="p-2 text-gray-500 hover:bg-gray-100 rounded-full transition"><Wallet size={20} /></button>
             )}
             <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 text-gray-500 hover:bg-gray-100 rounded-full relative">
                <Bell size={20} />
                {totalNotifications > 0 && <span className="absolute top-0 right-0 h-4 w-4 bg-red-500 rounded-full border-2 border-white text-[10px] text-white flex items-center justify-center font-bold">{totalNotifications}</span>}
             </button>
          </div>
        </header>

        <div className="flex-1 flex overflow-hidden">
           <div className="flex-1 overflow-auto bg-gray-50 relative">
              {renderContent()}
           </div>

           {/* Global Side Assistant */}
           {showAISidebar && (
             <div className="w-96 border-l border-gray-200 bg-white animate-slide-in-right shadow-2xl z-30 flex flex-col">
                <div className="p-4 bg-indigo-700 text-white flex justify-between items-center shadow-md">
                    <div className="flex items-center gap-2">
                        <Sparkles size={20} />
                        <span className="font-bold">Copilote Contextuel</span>
                    </div>
                    <button onClick={() => setShowAISidebar(false)} className="p-1 hover:bg-white/10 rounded-lg">
                        <ChevronRight size={20} />
                    </button>
