    >
      <div className="flex items-center gap-3">
        <Icon size={20} />
        <span className="font-bold text-sm">{label}</span>
      </div>
      {hasIndicator && <span className="h-2 w-2 bg-red-500 rounded-full animate-ping"></span>}
    </button>
  );
};

