    name: '',
    address: '',
    phone: '',
    adminName: '',
    adminUsername: '',
    adminPassword: ''
  });

  const handleCreatePharmacy = (e: React.FormEvent) => {
    e.preventDefault();
    setIsCreating(true);

    // 1. Create unique ID for the new pharmacy
    const pharmacyId = `pharma_${Date.now()}`;

    // 2. Create the Pharmacy object
    const newPharmacy: Pharmacy = {
      id: pharmacyId,
      name: newPharma.name,
      address: newPharma.address,
      phone: newPharma.phone,
      status: 'ACTIVE',
      createdAt: new Date()
    };

    // 3. Create the initial Admin user for this pharmacy
    const initialAdmin: User = {
      id: `user_${Date.now()}`,
      pharmacyId: pharmacyId,
      username: newPharma.adminUsername,
      password: newPharma.adminPassword,
      fullName: newPharma.adminName,
      role: 'ADMIN'
    };

    // Simulate API delay
    setTimeout(() => {
      setPharmacies([...pharmacies, newPharmacy]);
      setUsers([...users, initialAdmin]);
      setIsCreating(false);
      setIsModalOpen(false);
      setNewPharma({ name: '', address: '', phone: '', adminName: '', adminUsername: '', adminPassword: '' });
      alert(`Pharmacie "${newPharmacy.name}" créée avec succès. Admin: ${initialAdmin.username}`);
    }, 800);
  };

  const filteredPharmacies = pharmacies.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.address.toLowerCase().includes(searchTerm.toLowerCase())
