        return <Orders drugs={filteredDrugs} suppliers={filteredSuppliers} />;
      default:
        return null;
    }
  };

  const NavItem = ({ view, icon: Icon, label, allowedRoles }: { view: ViewState, icon: any, label: string, allowedRoles: UserRole[] }) => {
    if (!allowedRoles.includes(currentUser.role)) return null;
    const isActive = currentView === view;
    return (
      <button
        onClick={() => setCurrentView(view)}
        className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all duration-200 mb-1 ${
          isActive 
          ? 'bg-pharmacy-600 text-white shadow-md' 
          : 'text-gray-600 hover:bg-pharmacy-50 hover:text-pharmacy-700'
        }`}
      >
        <Icon size={20} className={isActive ? 'text-white' : 'text-gray-500'} />
        <span className="font-medium">{label}</span>
      </button>
    );
  };

  return (
    <div className="flex h-screen bg-gray-100 font-sans overflow-hidden text-sm md:text-base">
      <aside className="w-64 bg-white border-r border-gray-200 flex flex-col shadow-sm z-10">
        <div className="p-6 flex items-center space-x-3 border-b border-gray-100">
          <div className="bg-pharmacy-600 p-2 rounded-lg text-white shadow-md"><Activity size={24} /></div>
          <div>
            <h1 className="text-xl font-bold text-gray-800 tracking-tight">Fasopharm</h1>
            <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">{currentUser.role}</p>
          </div>
        </div>

        <nav className="flex-1 p-3 space-y-1 overflow-y-auto custom-scrollbar">
          {currentUser.role === 'SUPER_ADMIN' ? (
            <>
              <div className="px-4 py-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">Master Control</div>
              <NavItem view={ViewState.SUPER_ADMIN_DASHBOARD} icon={Globe} label="Réseau Global" allowedRoles={['SUPER_ADMIN']} />
              <NavItem view={ViewState.USERS} icon={Users} label="Tous les Staffs" allowedRoles={['SUPER_ADMIN']} />
              <NavItem view={ViewState.EXPORTS} icon={Database} label="Archives Cloud" allowedRoles={['SUPER_ADMIN']} />
            </>
          ) : (
            <>
              <div className="px-4 py-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                {pharmacies.find(p => p.id === currentPharmacyId)?.name || 'Espace Pharmacie'}
              </div>
              <NavItem view={ViewState.DASHBOARD} icon={LayoutDashboard} label="Tableau de Bord" allowedRoles={['ADMIN']} />
              <NavItem view={ViewState.POS} icon={ShoppingCart} label={currentUser.role === 'SELLER' ? "Préparation" : "Caisse"} allowedRoles={['ADMIN', 'CASHIER', 'SELLER']} />

              <div className="px-4 py-2 mt-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Logistique</div>
              <NavItem view={ViewState.INVENTORY} icon={Package} label="Stocks" allowedRoles={['ADMIN', 'AGENT']} />
              <NavItem view={ViewState.ORDERS} icon={ShoppingBag} label="Réappro" allowedRoles={['ADMIN', 'AGENT']} />

              <div className="px-4 py-2 mt-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Intelligence</div>
              <NavItem view={ViewState.ASSISTANT} icon={BrainCircuit} label="Assistant IA" allowedRoles={['ADMIN', 'AGENT', 'SELLER', 'CASHIER']} />
              <NavItem view={ViewState.SCANNER} icon={ScanLine} label="Scan Ordonnance" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} />

              {currentUser.role === 'ADMIN' && (
                <>
                  <div className="px-4 py-2 mt-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Gestion Locale</div>
                  <NavItem view={ViewState.SALES_HISTORY} icon={History} label="Historique Ventes" allowedRoles={['ADMIN']} />
                  <NavItem view={ViewState.USERS} icon={Users} label="Mon Personnel" allowedRoles={['ADMIN']} />
                </>
              )}
            </>
          )}
        </nav>

        <div className="p-4 border-t border-gray-100">
          <div className="mb-4 px-2">
            <p className="text-[10px] font-bold text-gray-400 uppercase">Utilisateur</p>
            <p className="font-bold text-gray-700 truncate">{currentUser.fullName}</p>
          </div>
          <button onClick={handleLogout} className="w-full flex items-center justify-center gap-2 p-2 text-red-600 hover:bg-red-50 rounded-lg transition text-sm font-bold">
            <LogOut size={18} /> Déconnexion
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-gray-200 flex items-center justify-between px-6 shadow-sm z-20">
          <h2 className="text-xl font-bold text-gray-800">{currentView}</h2>
          {currentUser.role !== 'SUPER_ADMIN' && (
            <div className="flex items-center gap-2 text-pharmacy-600 bg-pharmacy-50 px-3 py-1.5 rounded-full border border-pharmacy-100">
              <Building2 size={16} />
              <span className="text-xs font-black uppercase tracking-tight">{pharmacies.find(p => p.id === currentPharmacyId)?.name}</span>
            </div>
          )}
        </header>
        <div className="flex-1 overflow-auto bg-gray-50 relative">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { User, UserRole } from '../types';
import { UserPlus, Trash2, User as UserIcon, Edit2, X, ShieldCheck, Building2 } from 'lucide-react';

interface UserManagementProps {
  users: User[];
  setUsers: React.Dispatch<React.SetStateAction<User[]>>;
  currentUser: User; // Ajout du currentUser pour connaître sa pharmacie
}

const UserManagement: React.FC<UserManagementProps> = ({ users, setUsers, currentUser }) => {
  const [editingId, setEditingId] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    username: '',
    password: '',
    fullName: '',
    role: 'SELLER' as UserRole
  });

  // Filtrage : Si Admin, ne voit que sa pharma. Si Super Admin, voit tout.
  const displayUsers = currentUser.role === 'SUPER_ADMIN' 
    ? users 
    : users.filter(u => u.pharmacyId === currentUser.pharmacyId);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (editingId) {
      // Mise à jour
      setUsers(users.map(u => u.id === editingId ? { ...u, ...formData } : u));
      resetForm();
    } else {
      // Création : Injection CRITIQUE du pharmacyId
      const newUser: User = {
        id: `user_${Date.now()}`,
        pharmacyId: currentUser.role === 'SUPER_ADMIN' ? undefined : currentUser.pharmacyId,
        username: formData.username,
        password: formData.password,
        fullName: formData.fullName,
        role: formData.role
      };
      setUsers(prev => [...prev, newUser]);
      resetForm();
      alert(`Compte pour ${newUser.fullName} créé avec succès.`);
    }
  };

  const startEdit = (user: User) => {
    setEditingId(user.id);
    setFormData({
      username: user.username,
      password: user.password,
      fullName: user.fullName,
      role: user.role
    });
  };

  const resetForm = () => {
    setEditingId(null);
    setFormData({ username: '', password: '', fullName: '', role: 'SELLER' });
  };

  const handleDeleteUser = (id: string) => {
    const userToDelete = users.find(u => u.id === id);
    if (userToDelete?.role === 'ADMIN' && users.filter(u => u.role === 'ADMIN' && u.pharmacyId === currentUser.pharmacyId).length === 1) {
      alert("Impossible de supprimer le dernier administrateur de cette pharmacie.");
      return;
    }

    if (window.confirm(`Voulez-vous vraiment supprimer l'utilisateur ${userToDelete?.fullName} ?`)) {
      setUsers(prev => prev.filter(u => u.id !== id));
      if (editingId === id) resetForm();
    }
  };

  const getRoleBadge = (role: UserRole) => {
    switch (role) {
      case 'ADMIN': return <span className="px-2 py-1 bg-purple-100 text-purple-700 rounded-full text-[10px] font-black uppercase">Admin</span>;
      case 'AGENT': return <span className="px-2 py-1 bg-blue-100 text-blue-700 rounded-full text-[10px] font-black uppercase">Stock</span>;
      case 'SELLER': return <span className="px-2 py-1 bg-orange-100 text-orange-700 rounded-full text-[10px] font-black uppercase">Vendeur</span>;
      case 'CASHIER': return <span className="px-2 py-1 bg-green-100 text-green-700 rounded-full text-[10px] font-black uppercase">Caisse</span>;
      case 'SUPER_ADMIN': return <span className="px-2 py-1 bg-black text-white rounded-full text-[10px] font-black uppercase">Super Admin</span>;
      default: return null;
    }
  };

  return (
    <div className="p-6 h-full flex flex-col space-y-6 animate-fade-in bg-gray-50">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-black text-gray-800 tracking-tight">Gestion du Personnel</h2>
          <p className="text-sm text-gray-500">Configurez les accès de votre équipe locale</p>
        </div>
        {currentUser.pharmacyId && (
            <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-xl border border-gray-200 shadow-sm">
                <Building2 size={16} className="text-pharmacy-600" />
                <span className="text-xs font-bold text-gray-600">ID Pharma: {currentUser.pharmacyId}</span>
            </div>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Form Panel */}
        <div className="lg:col-span-1">
          <div className={`p-6 rounded-2xl shadow-sm border transition-all duration-300 ${editingId ? 'bg-indigo-50 border-indigo-200 ring-4 ring-indigo-50' : 'bg-white border-gray-100'}`}>
            <h3 className={`text-lg font-black mb-6 flex items-center gap-2 ${editingId ? 'text-indigo-800' : 'text-gray-800'}`}>
              {editingId ? <Edit2 size={20} /> : <UserPlus size={20} className="text-pharmacy-600" />}
              {editingId ? 'Modifier l\'Agent' : 'Nouveau Compte Staff'}
            </h3>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Nom Complet</label>
                <input required type="text" className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none bg-white transition"
                  placeholder="ex: Jean Dupont"
                  value={formData.fullName} onChange={e => setFormData({ ...formData, fullName: e.target.value })} />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Identifiant Connexion</label>
                <input required type="text" className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none bg-white transition"
                  placeholder="ex: j.dupont"
                  value={formData.username} onChange={e => setFormData({ ...formData, username: e.target.value })} />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Mot de passe</label>
                <input required type="text" className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none bg-white transition"
                  placeholder="••••••••"
                  value={formData.password} onChange={e => setFormData({ ...formData, password: e.target.value })} />
              </div>
              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Rôle & Permissions</label>
                <select className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none bg-white transition appearance-none"
                  value={formData.role} onChange={e => setFormData({ ...formData, role: e.target.value as UserRole })}>
                  <option value="SELLER">Vendeur (Préparation)</option>
                  <option value="CASHIER">Caissier (Encaissement)</option>
                  <option value="AGENT">Gestionnaire Stock</option>
                  <option value="ADMIN">Co-Administrateur</option>
                </select>
              </div>

              <div className="pt-4 flex gap-2">
                <button type="submit" className={`flex-1 py-4 rounded-xl text-white font-black shadow-lg transition transform active:scale-95 ${editingId ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-pharmacy-600 hover:bg-pharmacy-700'}`}>
                  {editingId ? 'Valider Modifs' : 'Activer le Compte'}
                </button>
                {editingId && (
                  <button type="button" onClick={resetForm} className="px-4 py-4 bg-white border border-gray-200 rounded-xl text-gray-400 hover:text-gray-600 hover:bg-gray-50 transition">
                    <X size={20} />
                  </button>
                )}
              </div>
            </form>
          </div>
        </div>

        {/* Users List */}
        <div className="lg:col-span-2">
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
             <div className="p-6 border-b border-gray-100 bg-white flex justify-between items-center">
               <h3 className="font-black text-gray-800 uppercase tracking-tight text-sm">Équipe Locale ({displayUsers.length})</h3>
               <div className="flex items-center gap-1 text-[10px] font-black text-green-600 bg-green-50 px-2 py-1 rounded-full">
                 <ShieldCheck size={12} /> SÉCURISÉ
               </div>
             </div>
             <div className="overflow-x-auto">
               <table className="w-full text-left">
                 <thead>
                   <tr className="bg-gray-50">
                     <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Membre</th>
                     <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Rôle</th>
                     <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Identifiant</th>
                     <th className="px-6 py-4 text-right text-[10px] font-black text-gray-400 uppercase tracking-widest">Actions</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-gray-100">
                   {displayUsers.map(user => (
                     <tr key={user.id} className={`${editingId === user.id ? 'bg-indigo-50' : 'hover:bg-gray-50'} transition`}>
                       <td className="px-6 py-4">
                         <div className="flex items-center">
                           <div className={`h-10 w-10 rounded-xl flex items-center justify-center mr-3 shadow-inner ${editingId === user.id ? 'bg-indigo-200 text-indigo-700' : 'bg-gray-100 text-gray-400'}`}>
                             <UserIcon size={20} />
                           </div>
                           <div>
                             <p className="text-sm font-bold text-gray-900">{user.fullName}</p>
                             {currentUser.role === 'SUPER_ADMIN' && <p className="text-[10px] text-gray-400">Pharma: {user.pharmacyId}</p>}
                           </div>
                         </div>
                       </td>
                       <td className="px-6 py-4">
                         {getRoleBadge(user.role)}
                       </td>
                       <td className="px-6 py-4 text-sm font-mono text-gray-500">
                         {user.username}
                       </td>
                       <td className="px-6 py-4 text-right">
                         <div className="flex justify-end gap-2">
                           <button 
                              onClick={() => startEdit(user)}
                              className="p-2 text-indigo-600 hover:bg-indigo-100 rounded-lg transition"
                              title="Modifier"
                           >
                             <Edit2 size={16} />
                           </button>
                           <button 
                              onClick={() => handleDeleteUser(user.id)}
                              className="p-2 text-red-600 hover:bg-red-100 rounded-lg transition"
                              title="Supprimer"
                           >
                             <Trash2 size={16} />
                           </button>
                         </div>
                       </td>
                     </tr>
                   ))}
                   {displayUsers.length === 0 && (
                     <tr>
                       <td colSpan={4} className="px-6 py-12 text-center">
                         <div className="flex flex-col items-center opacity-30">
                           <UserIcon size={48} className="mb-2" />
                           <p className="text-sm font-black uppercase tracking-widest">Aucun personnel enregistré</p>
                         </div>
                       </td>
                     </tr>
                   )}
                 </tbody>
               </table>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default UserManagement;

import React, { useState, useEffect } from 'react';
import { ViewState, Drug, Sale, User, UserRole, Supplier, Insurance, PendingOrder, Pharmacy } from './types';
import { INITIAL_DRUGS, INITIAL_USERS, INITIAL_SUPPLIERS, INITIAL_INSURANCES, INITIAL_PHARMACIES } from './constants';
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import POS from './components/POS';
import AIAssistant from './components/AIAssistant';
import PrescriptionScanner from './components/PrescriptionScanner';
import Login from './components/Login';
import UserManagement from './components/UserManagement';
import SalesHistory from './components/SalesHistory';
import Suppliers from './components/Suppliers';
import Insurances from './components/Insurances';
import DataExport from './components/DataExport';
import Orders from './components/Orders';
import CashClosing from './components/CashClosing';
import SuperAdminDashboard from './components/SuperAdminDashboard';

import { 
  LayoutDashboard, Package, ShoppingCart, Bot, ScanLine, Activity, LogOut, Users, Bell, 
  History, Truck, ShieldCheck, Database, ShoppingBag, Wallet,
  ChevronDown, ChevronRight, Layers, FileText, BrainCircuit, Building2, Globe
} from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>(INITIAL_PHARMACIES);
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  const [drugs, setDrugs] = useState<Drug[]>(INITIAL_DRUGS);
  const [sales, setSales] = useState<Sale[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>(INITIAL_SUPPLIERS);
  const [insurances, setInsurances] = useState<Insurance[]>(INITIAL_INSURANCES);
  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>([]);

  const [showNotifications, setShowNotifications] = useState(false);
  const [showCashClosing, setShowCashClosing] = useState(false);

  useEffect(() => {
    if (currentUser) {
      if (currentUser.role === 'SUPER_ADMIN') setCurrentView(ViewState.SUPER_ADMIN_DASHBOARD);
      else if (currentUser.role === 'CASHIER') setCurrentView(ViewState.POS);
      else if (currentUser.role === 'AGENT') setCurrentView(ViewState.INVENTORY);
      else if (currentUser.role === 'SELLER') setCurrentView(ViewState.POS);
      else setCurrentView(ViewState.DASHBOARD);
    }
  }, [currentUser]);

  const handleLogout = () => {
    setCurrentUser(null);
  };

  if (!currentUser) {
    return <Login users={users} onLogin={setCurrentUser} />;
  }

  // Filtrage des données par pharmacie pour les utilisateurs non-super-admin
  const currentPharmacyId = currentUser.pharmacyId;
  const filteredDrugs = currentUser.role === 'SUPER_ADMIN' ? drugs : drugs.filter(d => d.pharmacyId === currentPharmacyId);
  const filteredSales = currentUser.role === 'SUPER_ADMIN' ? sales : sales.filter(s => s.pharmacyId === currentPharmacyId);
  const filteredSuppliers = currentUser.role === 'SUPER_ADMIN' ? suppliers : suppliers.filter(s => s.pharmacyId === currentPharmacyId);
  const filteredInsurances = currentUser.role === 'SUPER_ADMIN' ? insurances : insurances.filter(i => i.pharmacyId === currentPharmacyId);

  const renderContent = () => {
    switch (currentView) {
      case ViewState.SUPER_ADMIN_DASHBOARD:
        return <SuperAdminDashboard pharmacies={pharmacies} setPharmacies={setPharmacies} users={users} setUsers={setUsers} />;
      case ViewState.DASHBOARD:
        return <Dashboard drugs={filteredDrugs} sales={filteredSales} />;
      case ViewState.INVENTORY:
        return <Inventory drugs={filteredDrugs} setDrugs={setDrugs} currentUser={currentUser} />;
      case ViewState.POS:
        return (
          <POS 
            drugs={filteredDrugs} setDrugs={setDrugs} insurances={filteredInsurances} 
            onSaleComplete={(s) => setSales([...sales, {...s, pharmacyId: currentPharmacyId || ''}])} 
            currentUser={currentUser} pendingOrders={pendingOrders} setPendingOrders={setPendingOrders}
          />
        );
      case ViewState.ASSISTANT:
        return <AIAssistant drugs={filteredDrugs} sales={filteredSales} suppliers={filteredSuppliers} insurances={filteredInsurances} />;
      case ViewState.SCANNER:
        return <PrescriptionScanner />;
      case ViewState.USERS:
        return <UserManagement users={users} setUsers={setUsers} currentUser={currentUser} />;
      case ViewState.SALES_HISTORY:
        return <SalesHistory sales={filteredSales} />;
      case ViewState.SUPPLIERS:
        return <Suppliers suppliers={filteredSuppliers} setSuppliers={setSuppliers} />;
      case ViewState.INSURANCES:
        return <Insurances insurances={filteredInsurances} setInsurances={setInsurances} />;
      case ViewState.EXPORTS:
        return <DataExport drugs={filteredDrugs} sales={filteredSales} users={users} suppliers={filteredSuppliers} insurances={filteredInsurances} />;
      case ViewState.ORDERS:
        return <Orders drugs={filteredDrugs} suppliers={filteredSuppliers} />;
      default:
        return null;
    }
  };

  const NavItem = ({ view, icon: Icon, label, allowedRoles }: { view: ViewState, icon: any, label: string, allowedRoles: UserRole[] }) => {
    if (!allowedRoles.includes(currentUser.role)) return null;
    const isActive = currentView === view;
    return (
      <button
        onClick={() => setCurrentView(view)}
        className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all duration-200 mb-1 ${
          isActive 
          ? 'bg-pharmacy-600 text-white shadow-md' 
          : 'text-gray-600 hover:bg-pharmacy-50 hover:text-pharmacy-700'
        }`}
      >
        <Icon size={20} className={isActive ? 'text-white' : 'text-gray-500'} />
        <span className="font-medium">{label}</span>
      </button>
    );
  };

  return (
    <div className="flex h-screen bg-gray-100 font-sans overflow-hidden text-sm md:text-base">
      <aside className="w-64 bg-white border-r border-gray-200 flex flex-col shadow-sm z-10">
        <div className="p-6 flex items-center space-x-3 border-b border-gray-100">
          <div className="bg-pharmacy-600 p-2 rounded-lg text-white shadow-md"><Activity size={24} /></div>
          <div>
            <h1 className="text-xl font-bold text-gray-800 tracking-tight">Fasopharm</h1>
            <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">{currentUser.role}</p>
          </div>
        </div>

        <nav className="flex-1 p-3 space-y-1 overflow-y-auto custom-scrollbar">
          {currentUser.role === 'SUPER_ADMIN' ? (
            <>
              <div className="px-4 py-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">Master Control</div>
              <NavItem view={ViewState.SUPER_ADMIN_DASHBOARD} icon={Globe} label="Réseau Global" allowedRoles={['SUPER_ADMIN']} />
              <NavItem view={ViewState.USERS} icon={Users} label="Tous les Staffs" allowedRoles={['SUPER_ADMIN']} />
              <NavItem view={ViewState.EXPORTS} icon={Database} label="Archives Cloud" allowedRoles={['SUPER_ADMIN']} />
            </>
          ) : (
            <>
              <div className="px-4 py-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                {pharmacies.find(p => p.id === currentPharmacyId)?.name || 'Espace Pharmacie'}
              </div>
              <NavItem view={ViewState.DASHBOARD} icon={LayoutDashboard} label="Tableau de Bord" allowedRoles={['ADMIN']} />
              <NavItem view={ViewState.POS} icon={ShoppingCart} label={currentUser.role === 'SELLER' ? "Préparation" : "Caisse"} allowedRoles={['ADMIN', 'CASHIER', 'SELLER']} />

              <div className="px-4 py-2 mt-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Logistique</div>
              <NavItem view={ViewState.INVENTORY} icon={Package} label="Stocks" allowedRoles={['ADMIN', 'AGENT']} />
              <NavItem view={ViewState.ORDERS} icon={ShoppingBag} label="Réappro" allowedRoles={['ADMIN', 'AGENT']} />

