import React, { useState } from 'react';
import { User, UserRole, Pharmacy } from '../types';
import { UserPlus, Trash2, User as UserIcon, Edit2, X, ShieldCheck, Building2, Search, CheckCircle } from 'lucide-react';

interface UserManagementProps {
  users: User[];
  setUsers: React.Dispatch<React.SetStateAction<User[]>>;
  currentUser: User;
  pharmacies?: Pharmacy[]; // Optionnel, requis pour le Super Admin
}

const UserManagement: React.FC<UserManagementProps> = ({ users, setUsers, currentUser, pharmacies = [] }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const [formData, setFormData] = useState({
    username: '',
    password: '',
    fullName: '',
    role: 'SELLER' as UserRole,
    pharmacyId: currentUser.pharmacyId || ''
  });

  const isSuperAdmin = currentUser.role === 'SUPER_ADMIN';

  // Filtrage des utilisateurs affichés
  const displayUsers = users.filter(u => {
    const belongsToMe = isSuperAdmin ? true : u.pharmacyId === currentUser.pharmacyId;
    const matchesSearch = u.fullName.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         u.username.toLowerCase().includes(searchTerm.toLowerCase());
    return belongsToMe && matchesSearch;
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (editingId) {
      setUsers(users.map(u => u.id === editingId ? { ...u, ...formData } : u));
      alert(`Compte de ${formData.fullName} mis à jour.`);
      resetForm();
    } else {
      const newUser: User = {
        id: `user_${Date.now()}`,
        pharmacyId: isSuperAdmin ? formData.pharmacyId : currentUser.pharmacyId,
        username: formData.username,
        password: formData.password,
        fullName: formData.fullName,
        role: formData.role
      };
      setUsers(prev => [...prev, newUser]);
      alert(`Nouveau compte créé pour ${newUser.fullName}.`);
      resetForm();
    }
  };

  const startEdit = (user: User) => {
    setEditingId(user.id);
    setFormData({
      username: user.username,
      password: user.password,
      fullName: user.fullName,
      role: user.role,
      pharmacyId: user.pharmacyId || ''
    });
  };

  const resetForm = () => {
    setEditingId(null);
    setFormData({ 
      username: '', 
      password: '', 
      fullName: '', 
      role: 'SELLER',
      pharmacyId: currentUser.pharmacyId || (pharmacies.length > 0 ? pharmacies[0].id : '')
    });
  };

  const getPharmacyName = (id?: string) => {
    if (!id) return "Système (Global)";
    return pharmacies.find(p => p.id === id)?.name || id;
  };

  const getRoleBadge = (role: UserRole) => {
    switch (role) {
      case 'ADMIN': return <span className="px-2 py-1 bg-purple-100 text-purple-700 rounded-full text-[10px] font-black uppercase">Admin</span>;
      case 'AGENT': return <span className="px-2 py-1 bg-blue-100 text-blue-700 rounded-full text-[10px] font-black uppercase">Stock</span>;
      case 'SELLER': return <span className="px-2 py-1 bg-orange-100 text-orange-700 rounded-full text-[10px] font-black uppercase">Vendeur</span>;
      case 'CASHIER': return <span className="px-2 py-1 bg-green-100 text-green-700 rounded-full text-[10px] font-black uppercase">Caisse</span>;
      case 'SUPER_ADMIN': return <span className="px-2 py-1 bg-black text-white rounded-full text-[10px] font-black uppercase">Super Admin</span>;
      default: return null;
    }
  };

  return (
    <div className="p-6 h-full flex flex-col space-y-6 bg-gray-50 overflow-y-auto">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-black text-gray-800 tracking-tight">Gestion du Personnel</h2>
          <p className="text-sm text-gray-500">
            {isSuperAdmin ? "Contrôle global des accès du réseau" : "Gérez l'équipe de votre officine"}
          </p>
        </div>
        {!isSuperAdmin && currentUser.pharmacyId && (
            <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-xl border border-gray-200 shadow-sm">
                <Building2 size={16} className="text-pharmacy-600" />
                <span className="text-xs font-bold text-gray-600">Pharma: {getPharmacyName(currentUser.pharmacyId)}</span>
            </div>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Form Panel */}
        <div className="lg:col-span-1">
          <div className={`p-6 rounded-2xl shadow-sm border transition-all duration-300 ${editingId ? 'bg-indigo-50 border-indigo-200' : 'bg-white border-gray-100'}`}>
            <h3 className={`text-lg font-black mb-6 flex items-center gap-2 ${editingId ? 'text-indigo-800' : 'text-gray-800'}`}>
              {editingId ? <Edit2 size={20} /> : <UserPlus size={20} className="text-pharmacy-600" />}
              {editingId ? 'Modifier Profil' : 'Recruter un Agent'}
            </h3>

            <form onSubmit={handleSubmit} className="space-y-4">
              {isSuperAdmin && (
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Assigner à la Pharmacie</label>
                  <select 
                    required
                    className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none bg-white transition"
                    value={formData.pharmacyId} 
                    onChange={e => setFormData({ ...formData, pharmacyId: e.target.value })}
                  >
                    <option value="">-- Sélectionner l'établissement --</option>
                    {pharmacies.map(p => (
                      <option key={p.id} value={p.id}>{p.name}</option>
                    ))}
                  </select>
                </div>
              )}

              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Nom Complet</label>
                <input required type="text" className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none bg-white transition"
                  placeholder="ex: Jean Dupont"
                  value={formData.fullName} onChange={e => setFormData({ ...formData, fullName: e.target.value })} />
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Identifiant</label>
                  <input required type="text" className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none bg-white transition"
                    placeholder="j.dupont"
                    value={formData.username} onChange={e => setFormData({ ...formData, username: e.target.value })} />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Mot de passe</label>
                  <input required type="text" className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none bg-white transition"
                    placeholder="••••••••"
                    value={formData.password} onChange={e => setFormData({ ...formData, password: e.target.value })} />
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Rôle Système</label>
                <select className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none bg-white transition appearance-none"
                  value={formData.role} onChange={e => setFormData({ ...formData, role: e.target.value as UserRole })}>
                  <option value="SELLER">Vendeur / Préparateur</option>
                  <option value="CASHIER">Caissier principal</option>
                  <option value="AGENT">Gestionnaire de Stock</option>
                  <option value="ADMIN">Administrateur de Pharmacie</option>
                  {isSuperAdmin && <option value="SUPER_ADMIN">Super Administrateur</option>}
                </select>
              </div>

              <div className="pt-4 flex gap-2">
                <button type="submit" className={`flex-1 py-4 rounded-xl text-white font-black shadow-lg transition transform active:scale-95 ${editingId ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-pharmacy-600 hover:bg-pharmacy-700'}`}>
                  {editingId ? 'Valider Modifs' : 'Créer le Compte'}
                </button>
                {editingId && (
                  <button type="button" onClick={resetForm} className="px-4 py-4 bg-white border border-gray-200 rounded-xl text-gray-400 hover:text-gray-600 transition">
                    <X size={20} />
                  </button>
                )}
              </div>
            </form>
          </div>
        </div>

        {/* List Panel */}
        <div className="lg:col-span-2">
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
             <div className="p-6 border-b border-gray-100 flex flex-col md:flex-row justify-between items-center gap-4">
               <h3 className="font-black text-gray-800 uppercase tracking-tight text-sm">Répertoire des Staffs ({displayUsers.length})</h3>
               <div className="relative w-full md:w-64">
                 <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                 <input 
                  type="text" 
                  placeholder="Chercher un nom..." 
                  className="w-full pl-10 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg text-xs outline-none focus:ring-2 focus:ring-pharmacy-500"
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                 />
               </div>
             </div>
             <div className="overflow-x-auto">
               <table className="w-full text-left">
                 <thead>
                   <tr className="bg-gray-50">
                     <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Utilisateur</th>
                     <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Rôle</th>
                     <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Pharmacie</th>
                     <th className="px-6 py-4 text-right text-[10px] font-black text-gray-400 uppercase tracking-widest">Actions</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-gray-100">
                   {displayUsers.map(user => (
                     <tr key={user.id} className={`${editingId === user.id ? 'bg-indigo-50' : 'hover:bg-gray-50'} transition`}>
                       <td className="px-6 py-4">
                         <div className="flex items-center">
                           <div className={`h-10 w-10 rounded-xl flex items-center justify-center mr-3 shadow-inner ${user.role === 'ADMIN' ? 'bg-purple-100 text-purple-600' : 'bg-gray-100 text-gray-400'}`}>
                             <UserIcon size={20} />
                           </div>
                           <div>
                             <p className="text-sm font-bold text-gray-900">{user.fullName}</p>
                             <p className="text-[10px] text-gray-400 font-mono">{user.username}</p>
                           </div>
                         </div>
                       </td>
                       <td className="px-6 py-4">
                         {getRoleBadge(user.role)}
                       </td>
                       <td className="px-6 py-4">
                          <div className="flex items-center gap-2 text-xs text-gray-600 font-medium">
                            <Building2 size={14} className="text-gray-400" />
                            {getPharmacyName(user.pharmacyId)}
                          </div>
                       </td>
                       <td className="px-6 py-4 text-right">
                         <div className="flex justify-end gap-2">
                           <button onClick={() => startEdit(user)} className="p-2 text-indigo-600 hover:bg-indigo-100 rounded-lg transition"><Edit2 size={16} /></button>
                           {user.id !== currentUser.id && (
                             <button 
                               onClick={() => {
                                 if (window.confirm("Supprimer ce compte ?")) setUsers(prev => prev.filter(u => u.id !== user.id));
                               }} 
                               className="p-2 text-red-600 hover:bg-red-100 rounded-lg transition"
                             >
                               <Trash2 size={16} />
                             </button>
                           )}
                         </div>
                       </td>
                     </tr>
                   ))}
                 </tbody>
               </table>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default UserManagement;

import React, { useState, useEffect } from 'react';
import { ViewState, Drug, Sale, User, UserRole, Supplier, Insurance, PendingOrder, Pharmacy } from './types';
import { INITIAL_DRUGS, INITIAL_USERS, INITIAL_SUPPLIERS, INITIAL_INSURANCES, INITIAL_PHARMACIES } from './constants';
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import POS from './components/POS';
import AIAssistant from './components/AIAssistant';
import PrescriptionScanner from './components/PrescriptionScanner';
import Login from './components/Login';
import UserManagement from './components/UserManagement';
import SalesHistory from './components/SalesHistory';
import Suppliers from './components/Suppliers';
import Insurances from './components/Insurances';
import DataExport from './components/DataExport';
import Orders from './components/Orders';
import CashClosing from './components/CashClosing';
import SuperAdminDashboard from './components/SuperAdminDashboard';

import { 
  LayoutDashboard, Package, ShoppingCart, Bot, ScanLine, Activity, LogOut, Users, Bell, 
  History, Truck, ShieldCheck, Database, ShoppingBag, Wallet,
  ChevronDown, ChevronRight, Layers, FileText, BrainCircuit, Building2, Globe
} from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>(INITIAL_PHARMACIES);
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  const [drugs, setDrugs] = useState<Drug[]>(INITIAL_DRUGS);
  const [sales, setSales] = useState<Sale[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>(INITIAL_SUPPLIERS);
  const [insurances, setInsurances] = useState<Insurance[]>(INITIAL_INSURANCES);
  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>([]);

  const [showNotifications, setShowNotifications] = useState(false);
  const [showCashClosing, setShowCashClosing] = useState(false);

  useEffect(() => {
    if (currentUser) {
      if (currentUser.role === 'SUPER_ADMIN') setCurrentView(ViewState.SUPER_ADMIN_DASHBOARD);
      else if (currentUser.role === 'CASHIER') setCurrentView(ViewState.POS);
      else if (currentUser.role === 'AGENT') setCurrentView(ViewState.INVENTORY);
      else if (currentUser.role === 'SELLER') setCurrentView(ViewState.POS);
      else setCurrentView(ViewState.DASHBOARD);
    }
  }, [currentUser]);

  const handleLogout = () => {
    setCurrentUser(null);
  };

  if (!currentUser) {
    return <Login users={users} onLogin={setCurrentUser} />;
  }

  // Filtrage des données par pharmacie pour les utilisateurs non-super-admin
  const currentPharmacyId = currentUser.pharmacyId;
  const filteredDrugs = currentUser.role === 'SUPER_ADMIN' ? drugs : drugs.filter(d => d.pharmacyId === currentPharmacyId);
  const filteredSales = currentUser.role === 'SUPER_ADMIN' ? sales : sales.filter(s => s.pharmacyId === currentPharmacyId);
  const filteredSuppliers = currentUser.role === 'SUPER_ADMIN' ? suppliers : suppliers.filter(s => s.pharmacyId === currentPharmacyId);
  const filteredInsurances = currentUser.role === 'SUPER_ADMIN' ? insurances : insurances.filter(i => i.pharmacyId === currentPharmacyId);

  const renderContent = () => {
    switch (currentView) {
      case ViewState.SUPER_ADMIN_DASHBOARD:
        return <SuperAdminDashboard pharmacies={pharmacies} setPharmacies={setPharmacies} users={users} setUsers={setUsers} />;
      case ViewState.DASHBOARD:
        return <Dashboard drugs={filteredDrugs} sales={filteredSales} />;
      case ViewState.INVENTORY:
        return <Inventory drugs={filteredDrugs} setDrugs={setDrugs} currentUser={currentUser} />;
      case ViewState.POS:
        return (
          <POS 
            drugs={filteredDrugs} setDrugs={setDrugs} insurances={filteredInsurances} 
            onSaleComplete={(s) => setSales([...sales, {...s, pharmacyId: currentPharmacyId || ''}])} 
            currentUser={currentUser} pendingOrders={pendingOrders} setPendingOrders={setPendingOrders}
          />
        );
      case ViewState.ASSISTANT:
        return <AIAssistant drugs={filteredDrugs} sales={filteredSales} suppliers={filteredSuppliers} insurances={filteredInsurances} />;
      case ViewState.SCANNER:
        return <PrescriptionScanner />;
      case ViewState.USERS:
        return <UserManagement users={users} setUsers={setUsers} currentUser={currentUser} pharmacies={pharmacies} />;
      case ViewState.SALES_HISTORY:
        return <SalesHistory sales={filteredSales} />;
      case ViewState.SUPPLIERS:
        return <Suppliers suppliers={filteredSuppliers} setSuppliers={setSuppliers} />;
      case ViewState.INSURANCES:
        return <Insurances insurances={filteredInsurances} setInsurances={setInsurances} />;
      case ViewState.EXPORTS:
        return <DataExport drugs={filteredDrugs} sales={filteredSales} users={users} suppliers={filteredSuppliers} insurances={filteredInsurances} />;
      case ViewState.ORDERS:
        return <Orders drugs={filteredDrugs} suppliers={filteredSuppliers} />;
      default:
        return null;
    }
  };

  const NavItem = ({ view, icon: Icon, label, allowedRoles }: { view: ViewState, icon: any, label: string, allowedRoles: UserRole[] }) => {
    if (!allowedRoles.includes(currentUser.role)) return null;
    const isActive = currentView === view;
    return (
      <button
        onClick={() => setCurrentView(view)}
        className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all duration-200 mb-1 ${
          isActive 
          ? 'bg-pharmacy-600 text-white shadow-md' 
          : 'text-gray-600 hover:bg-pharmacy-50 hover:text-pharmacy-700'
        }`}
      >
        <Icon size={20} className={isActive ? 'text-white' : 'text-gray-500'} />
        <span className="font-medium">{label}</span>
      </button>
    );
  };

  return (
    <div className="flex h-screen bg-gray-100 font-sans overflow-hidden text-sm md:text-base">
      <aside className="w-64 bg-white border-r border-gray-200 flex flex-col shadow-sm z-10">
        <div className="p-6 flex items-center space-x-3 border-b border-gray-100">
          <div className="bg-pharmacy-600 p-2 rounded-lg text-white shadow-md"><Activity size={24} /></div>
          <div>
            <h1 className="text-xl font-bold text-gray-800 tracking-tight">Fasopharm</h1>
            <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">{currentUser.role}</p>
          </div>
        </div>

        <nav className="flex-1 p-3 space-y-1 overflow-y-auto custom-scrollbar">
          {currentUser.role === 'SUPER_ADMIN' ? (
            <>
              <div className="px-4 py-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">Master Control</div>
              <NavItem view={ViewState.SUPER_ADMIN_DASHBOARD} icon={Globe} label="Réseau Global" allowedRoles={['SUPER_ADMIN']} />
              <NavItem view={ViewState.USERS} icon={Users} label="Tous les Staffs" allowedRoles={['SUPER_ADMIN']} />
              <NavItem view={ViewState.EXPORTS} icon={Database} label="Archives Cloud" allowedRoles={['SUPER_ADMIN']} />
            </>
          ) : (
            <>
              <div className="px-4 py-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                {pharmacies.find(p => p.id === currentPharmacyId)?.name || 'Espace Pharmacie'}
              </div>
              <NavItem view={ViewState.DASHBOARD} icon={LayoutDashboard} label="Tableau de Bord" allowedRoles={['ADMIN']} />
              <NavItem view={ViewState.POS} icon={ShoppingCart} label={currentUser.role === 'SELLER' ? "Préparation" : "Caisse"} allowedRoles={['ADMIN', 'CASHIER', 'SELLER']} />

              <div className="px-4 py-2 mt-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Logistique</div>
              <NavItem view={ViewState.INVENTORY} icon={Package} label="Stocks" allowedRoles={['ADMIN', 'AGENT']} />
              <NavItem view={ViewState.ORDERS} icon={ShoppingBag} label="Réappro" allowedRoles={['ADMIN', 'AGENT']} />

              <div className="px-4 py-2 mt-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Intelligence</div>
              <NavItem view={ViewState.ASSISTANT} icon={BrainCircuit} label="Assistant IA" allowedRoles={['ADMIN', 'AGENT', 'SELLER', 'CASHIER']} />
              <NavItem view={ViewState.SCANNER} icon={ScanLine} label="Scan Ordonnance" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} />

              {currentUser.role === 'ADMIN' && (
                <>
                  <div className="px-4 py-2 mt-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Gestion Locale</div>
                  <NavItem view={ViewState.SALES_HISTORY} icon={History} label="Historique Ventes" allowedRoles={['ADMIN']} />
                  <NavItem view={ViewState.USERS} icon={Users} label="Mon Personnel" allowedRoles={['ADMIN']} />
                </>
              )}
            </>
          )}
        </nav>

        <div className="p-4 border-t border-gray-100">
          <div className="mb-4 px-2">
            <p className="text-[10px] font-bold text-gray-400 uppercase">Utilisateur</p>
            <p className="font-bold text-gray-700 truncate">{currentUser.fullName}</p>
          </div>
          <button onClick={handleLogout} className="w-full flex items-center justify-center gap-2 p-2 text-red-600 hover:bg-red-50 rounded-lg transition text-sm font-bold">
            <LogOut size={18} /> Déconnexion
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-gray-200 flex items-center justify-between px-6 shadow-sm z-20">
          <h2 className="text-xl font-bold text-gray-800">{currentView}</h2>
          {currentUser.role !== 'SUPER_ADMIN' && (
            <div className="flex items-center gap-2 text-pharmacy-600 bg-pharmacy-50 px-3 py-1.5 rounded-full border border-pharmacy-100">
              <Building2 size={16} />
              <span className="text-xs font-black uppercase tracking-tight">{pharmacies.find(p => p.id === currentPharmacyId)?.name}</span>
            </div>
          )}
        </header>
        <div className="flex-1 overflow-auto bg-gray-50 relative">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Drug, CartItem, Sale, PaymentMethod, User, Insurance, PendingOrder } from '../types';
import { ShoppingCart, Plus, Minus, Trash, Search, AlertOctagon, CreditCard, Banknote, Smartphone, Printer, CheckCircle, ShieldCheck, Camera, Loader2, User as UserIcon, FileText, Send, Clock, X, RefreshCw, ChevronDown, ChevronUp, Coins } from 'lucide-react';
import { checkDrugInteractions, analyzeMedicineBox } from '../services/geminiService';

interface POSProps {
  drugs: Drug[];
  setDrugs: React.Dispatch<React.SetStateAction<Drug[]>>;
  insurances: Insurance[];
  onSaleComplete: (sale: Sale) => void;
  currentUser: User;
  pendingOrders: PendingOrder[];
  setPendingOrders: React.Dispatch<React.SetStateAction<PendingOrder[]>>;
}

const POS: React.FC<POSProps> = ({ drugs, setDrugs, insurances, onSaleComplete, currentUser, pendingOrders, setPendingOrders }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [interactionAlert, setInteractionAlert] = useState<string | null>(null);
  const [isChecking, setIsChecking] = useState(false);
  const [isScanning, setIsScanning] = useState(false);

  // Insurance State
  const [showInsurance, setShowInsurance] = useState(false);
  const [selectedInsuranceId, setSelectedInsuranceId] = useState<string>('');
  const [coverageRate, setCoverageRate] = useState<number>(0);

  // Patient Info State (for Insurance)
  const [patientName, setPatientName] = useState('');
  const [policyNumber, setPolicyNumber] = useState('');

  // Payment State
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('CASH');
  const [amountReceived, setAmountReceived] = useState<number | ''>(''); 

  const [showReceipt, setShowReceipt] = useState<Sale | null>(null);
  const [showPendingTicket, setShowPendingTicket] = useState<PendingOrder | null>(null);

  // Determine Mode
  const isPreparer = currentUser.role === 'SELLER' || currentUser.role === 'AGENT';
  const isCashier = currentUser.role === 'CASHIER' || currentUser.role === 'ADMIN';

  // Refs for auto-focus
  const searchInputRef = useRef<HTMLInputElement>(null);
  const cashInputRef = useRef<HTMLInputElement>(null);

  // CRITICAL: Filter pending orders strictly by current pharmacy
  const localPendingOrders = pendingOrders.filter(order => order.pharmacyId === currentUser.pharmacyId);

  // Derived calculations
  const totalAmount = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const insuranceAmount = selectedInsuranceId ? Math.round(totalAmount * (coverageRate / 100)) : 0;
  const patientAmount = totalAmount - insuranceAmount;

  // Change Logic
  const amountToPay = patientAmount; 
  const changeDue = typeof amountReceived === 'number' ? amountReceived - amountToPay : 0;
  const isAmountSufficient = paymentMethod !== 'CASH' || (typeof amountReceived === 'number' && amountReceived >= amountToPay);

  useEffect(() => {
    // Focus search on load
    if (searchInputRef.current) searchInputRef.current.focus();
  }, []);

  useEffect(() => {
    // Focus cash input when selecting CASH payment method
    if (paymentMethod === 'CASH' && cart.length > 0 && cashInputRef.current) {
        cashInputRef.current.focus();
    }
  }, [paymentMethod, cart.length]);

  const handleInsuranceChange = (id: string) => {
    setSelectedInsuranceId(id);
    if (id) {
      const ins = insurances.find(i => i.id === id);
      setCoverageRate(ins ? ins.defaultCoverage : 0);
    } else {
      setCoverageRate(0);
      setPatientName('');
      setPolicyNumber('');
    }
  };

  const addToCart = (drug: Drug) => {
    const existing = cart.find(item => item.id === drug.id);
    if (existing) {
      if (existing.quantity < drug.stock) {
        setCart(cart.map(item => item.id === drug.id ? { ...item, quantity: item.quantity + 1 } : item));
      } else {
        alert("Stock insuffisant !");
      }
    } else {
      if (drug.stock > 0) {
        setCart([...cart, { ...drug, quantity: 1 }]);
      } else {
        alert("Produit en rupture de stock.");
      }
    }
    setSearchTerm(''); // Clear search after adding
    if (searchInputRef.current) searchInputRef.current.focus();
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        const drug = drugs.find(d => d.id === id);
        if (newQty > 0 && drug && newQty <= drug.stock) {
          return { ...item, quantity: newQty };
        }
      }
      return item;
    }));
  };

  const clearCart = () => {
      if (window.confirm("Voulez-vous vraiment annuler la préparation et vider le panier ?")) {
          setCart([]);
          setSelectedInsuranceId('');
          setPatientName('');
          setPolicyNumber('');
          setAmountReceived('');
      }
  };

  const checkInteractions = async () => {
    if (cart.length < 2) return;
    setIsChecking(true);
    setInteractionAlert(null);
    const names = cart.map(c => c.name);
    const result = await checkDrugInteractions(names);
    setInteractionAlert(result);
    setIsChecking(false);
  };

  const handleCameraScan = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setIsScanning(true);
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = reader.result as string;
        try {
          const result = await analyzeMedicineBox(base64String);
          if (result && result.name) {
            const scannedName = result.name.toLowerCase();
            const foundDrug = drugs.find(d => 
              d.name.toLowerCase().includes(scannedName) || 
              scannedName.includes(d.name.toLowerCase())
            );
            if (foundDrug) {
              addToCart(foundDrug);
            } else {
              alert(`Produit identifié comme "${result.name}" mais non trouvé dans le stock.`);
            }
          } else {
            alert("Impossible d'identifier le produit on l'image.");
          }
        } catch (error) {
          console.error("Scan error", error);
          alert("Erreur lors de l'analyse.");
        }
        setIsScanning(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSendToCashier = () => {
    if (cart.length === 0) return;
    const newOrder: PendingOrder = {
      id: Date.now().toString(),
      pharmacyId: currentUser.pharmacyId || '', // Assurer le lien avec la pharmacie
      ticketNumber: `A-${Math.floor(Math.random() * 900) + 100}`,
      timestamp: new Date(),
      items: [...cart],
      total: totalAmount,
      preparedBy: currentUser.fullName,
      insuranceId: selectedInsuranceId,
      patientName,
      policyNumber
    };
    setPendingOrders(prev => [...prev, newOrder]);
    setCart([]);
    setSelectedInsuranceId('');
    setCoverageRate(0);
    setPatientName('');
    setPolicyNumber('');
    setAmountReceived('');
    setShowPendingTicket(newOrder);
  };

  const loadPendingOrder = (order: PendingOrder) => {
    setCart(order.items);
    if (order.insuranceId) {
       setShowInsurance(true);
       handleInsuranceChange(order.insuranceId);
       setPatientName(order.patientName || '');
       setPolicyNumber(order.policyNumber || '');
    }
    setPendingOrders(prev => prev.filter(o => o.id !== order.id));
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;

    if (selectedInsuranceId) {
      if (!patientName.trim() || !policyNumber.trim()) {
        alert("Veuillez entrer les informations du patient assuré.");
        return;
      }
    }

    if (!isAmountSufficient) {
       alert("Le montant reçu est insuffisant.");
       return;
    }

    const newDrugs = drugs.map(d => {
      const cartItem = cart.find(c => c.id === d.id);
      if (cartItem) {
        return { ...d, stock: d.stock - cartItem.quantity };
      }
      return d;
    });
    setDrugs(newDrugs);

    const selectedIns = insurances.find(i => i.id === selectedInsuranceId);
    const sale: Sale = {
      id: Date.now().toString(),
      pharmacyId: currentUser.pharmacyId || '',
      timestamp: new Date(),
      items: [...cart],
      total: totalAmount,
      paymentMethod: paymentMethod,
      servedBy: currentUser.fullName,
      insuranceId: selectedInsuranceId || undefined,
      insuranceName: selectedIns?.name,
      insuranceCoverageRate: selectedInsuranceId ? coverageRate : undefined,
      insuranceAmount: selectedInsuranceId ? insuranceAmount : 0,
      patientAmount: patientAmount,
      patientName: selectedInsuranceId ? patientName : undefined,
      policyNumber: selectedInsuranceId ? policyNumber : undefined,
      amountReceived: paymentMethod === 'CASH' && typeof amountReceived === 'number' ? amountReceived : undefined,
      changeGiven: paymentMethod === 'CASH' ? changeDue : undefined
    };

    onSaleComplete(sale);
    setCart([]);
    setInteractionAlert(null);
    setSelectedInsuranceId('');
    setCoverageRate(0);
    setPatientName('');
    setPolicyNumber('');
    setAmountReceived('');
    setShowInsurance(false);
    setShowReceipt(sale);
  };

  const filteredDrugs = drugs.filter(d => d.name.toLowerCase().includes(searchTerm.toLowerCase()));
  const formatCurrency = (value: number) => value.toLocaleString('fr-FR') + ' FCFA';

  // COMPONENTS
  const PendingTicketModal = () => {
      if (!showPendingTicket) return null;
      return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-60 backdrop-blur-sm animate-fade-in">
            <div className="bg-white p-6 rounded-xl shadow-2xl w-80 text-center">
                <div className="w-16 h-16 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4">
                    <CheckCircle size={32} />
                </div>
                <h3 className="text-xl font-bold text-gray-800">Commande Envoyée !</h3>
                <div className="bg-gray-100 p-4 rounded-lg border border-dashed border-gray-300 my-6">
                    <p className="text-xs text-gray-500 uppercase">Numéro Ticket</p>
                    <p className="text-4xl font-mono font-bold text-gray-900">{showPendingTicket.ticketNumber}</p>
                </div>
                <button onClick={() => setShowPendingTicket(null)} className="w-full py-3 bg-pharmacy-600 text-white rounded-lg hover:bg-pharmacy-700 font-bold">
                    OK
                </button>
            </div>
        </div>
      );
  }

  const ReceiptModal = () => {
    if (!showReceipt) return null;
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-60 backdrop-blur-sm animate-fade-in">
        <div className="bg-white rounded-lg shadow-2xl w-96 overflow-hidden flex flex-col max-h-[90vh]">
          <div className="bg-pharmacy-600 text-white p-4 text-center">
            <div className="mx-auto bg-white/20 rounded-full w-12 h-12 flex items-center justify-center mb-2">
              <Printer size={24} />
            </div>
            <h3 className="font-bold text-lg">Impression Reçu</h3>
          </div>

          <div className="p-6 bg-white font-mono text-sm overflow-y-auto flex-1">
            <div className="text-center mb-4">
              <p className="font-bold text-xl uppercase tracking-wider">Fasopharm</p>
              <p className="text-xs text-gray-500">Ouagadougou, Burkina Faso</p>
            </div>

            <div className="border-b border-dashed border-gray-300 my-4"></div>

            <div className="flex justify-between text-xs mb-2">
              <span>Date: {new Date(showReceipt.timestamp).toLocaleDateString()}</span>
              <span>{new Date(showReceipt.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
            </div>

            {showReceipt.insuranceName && (
              <div className="my-3 border border-gray-300 p-2 rounded text-xs bg-gray-50">
                <p className="font-bold">TIERS-PAYANT: {showReceipt.insuranceName}</p>
                <p>Patient: {showReceipt.patientName}</p>
                <p>Matricule: {showReceipt.policyNumber}</p>
              </div>
            )}

            <div className="space-y-2 mb-4">
              {showReceipt.items.map((item, idx) => (
                <div key={idx} className="flex justify-between">
                  <span>{item.quantity} x {item.name}</span>
                  <span>{formatCurrency(item.price * item.quantity)}</span>
                </div>
              ))}
            </div>

            <div className="border-b border-dashed border-gray-300 my-4"></div>

            <div className="flex justify-between font-bold text-gray-600 my-1">
              <span>Total</span>
              <span>{formatCurrency(showReceipt.total)}</span>
            </div>

            {showReceipt.insuranceName && (
               <div className="flex justify-between text-gray-600 my-1">
                   <span>Part Assurance ({showReceipt.insuranceCoverageRate}%)</span>
                   <span>-{formatCurrency(showReceipt.insuranceAmount || 0)}</span>
               </div>
            )}

            <div className="flex justify-between font-bold text-xl my-2 text-gray-900 pt-2 border-t border-gray-200">
              <span>NET À PAYER</span>
              <span>{formatCurrency(showReceipt.patientAmount || showReceipt.total)}</span>
            </div>

             {showReceipt.paymentMethod === 'CASH' && showReceipt.amountReceived !== undefined && (
                <div className="mt-2 text-right">
                  <div className="text-xs text-gray-500">Espèces Reçu: {formatCurrency(showReceipt.amountReceived)}</div>
                  <div className="font-bold text-gray-800">Monnaie: {formatCurrency(showReceipt.changeGiven || 0)}</div>
                </div>
             )}

            <div className="text-center mt-8 text-xs text-gray-400">
              <p>*** Merci de votre visite ***</p>
            </div>
          </div>

          <div className="p-4 bg-gray-50 flex space-x-3 border-t border-gray-200">
             <button onClick={() => setShowReceipt(null)} className="flex-1 py-3 bg-gray-200 text-gray-800 rounded-lg hover:bg-gray-300 font-bold">Fermer</button>
             <button onClick={() => { window.print(); setShowReceipt(null); }} className="flex-1 py-3 bg-pharmacy-600 text-white rounded-lg hover:bg-pharmacy-700 font-bold flex justify-center items-center gap-2">
               <Printer size={18} /> Imprimer
             </button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="flex h-full bg-gray-100 overflow-hidden relative">
      {showReceipt && <ReceiptModal />}
      {showPendingTicket && <PendingTicketModal />}

      {/* 1. LEFT SIDEBAR: PENDING ORDERS (Cashier Only) - Filtered by Pharmacy */}
      {isCashier && localPendingOrders.length > 0 && (
          <div className="w-64 bg-white border-r border-gray-200 flex flex-col z-20 shadow-lg">
              <div className="p-4 bg-orange-50 border-b border-orange-100 flex items-center justify-between">
                  <h3 className="font-bold text-orange-800 flex items-center gap-2 text-sm">
                      <Clock size={16} /> File d'Attente
                  </h3>
                  <span className="bg-orange-200 text-orange-800 text-xs px-2 py-1 rounded-full">{localPendingOrders.length}</span>
              </div>
              <div className="flex-1 overflow-y-auto p-2 space-y-2">
                  {localPendingOrders.map(order => (
                      <div 
                        key={order.id} 
                        onClick={() => loadPendingOrder(order)}
                        className="p-3 bg-white border border-gray-200 rounded-lg hover:border-orange-400 hover:shadow-md cursor-pointer transition relative group"
                      >
                          <div className="flex justify-between items-start mb-2">
                              <span className="font-mono font-bold text-gray-800 bg-gray-100 px-2 py-0.5 rounded text-lg">{order.ticketNumber}</span>
                              <span className="text-xs text-gray-400">{new Date(order.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                          </div>
                          <div className="flex justify-between items-end">
                              <div className="text-xs text-gray-500">
                                {order.items.length} art. <br/>
                                <span className="italic text-pharmacy-600 font-bold">par {order.preparedBy.split(' ')[0]}</span>
                              </div>
                              <span className="font-bold text-gray-900">{formatCurrency(order.total)}</span>
                          </div>
                      </div>
                  ))}
              </div>
          </div>
      )}

      {/* 2. CENTER: PRODUCT GRID */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        {/* Search Bar */}
        <div className="p-4 bg-white border-b border-gray-200 shadow-sm z-10">
           <div className="flex gap-4 max-w-4xl mx-auto">
              <div className="relative flex-1">
                <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
                <input 
                  ref={searchInputRef}
                  type="text" 
                  placeholder="Rechercher (Nom, Catégorie)..." 
                  className="w-full pl-12 pr-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-pharmacy-500 text-lg shadow-sm"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
              <label className={`flex items-center gap-2 px-6 py-3 rounded-xl cursor-pointer transition border border-gray-300 shadow-sm ${isScanning ? 'bg-gray-100 text-gray-400' : 'bg-white text-gray-700 hover:bg-gray-50'}`}>
                 {isScanning ? <Loader2 className="animate-spin" size={20} /> : <Camera size={20} />}
                 <span className="font-bold hidden md:inline">{isScanning ? '...' : 'Scan'}</span>
                 <input type="file" accept="image/*" className="hidden" onChange={handleCameraScan} disabled={isScanning} />
              </label>
           </div>
        </div>

        {/* Grid */}
        <div className="flex-1 overflow-y-auto p-4 bg-gray-50">
           <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4 max-w-6xl mx-auto pb-20">
              {filteredDrugs.map(drug => (
                <div key={drug.id} 
                  onClick={() => addToCart(drug)}
                  className={`bg-white p-4 rounded-xl border transition shadow-sm hover:shadow-lg cursor-pointer flex flex-col justify-between h-48 group select-none relative overflow-hidden ${drug.stock === 0 ? 'opacity-50 border-gray-200 pointer-events-none' : 'border-gray-100 hover:border-pharmacy-400'}`}
                >
                  {drug.stock < 20 && drug.stock > 0 && (
                      <div className="absolute top-0 right-0 bg-red-500 text-white text-[10px] px-2 py-0.5 rounded-bl-lg font-bold">
                          Stock Bas
                      </div>
                  )}
                  <div>
                    <h3 className="font-bold text-gray-800 leading-tight mb-1">{drug.name}</h3>
                    <p className="text-xs text-gray-500">{drug.category}</p>
                    <p className="text-xs text-gray-400">{drug.dosage}</p>
                  </div>
                  <div className="mt-2">
                    <div className="flex justify-between items-end">
                      <span className="font-bold text-pharmacy-600 text-xl">{formatCurrency(drug.price).split(' ')[0]} <span className="text-xs text-gray-400">FCFA</span></span>
                    </div>
                    <div className={`text-xs mt-1 font-medium ${drug.stock > 0 ? 'text-green-600' : 'text-red-500'}`}>
                       {drug.stock > 0 ? `${drug.stock} en stock` : 'Rupture'}
                    </div>
                  </div>
                  {/* Hover effect overlay */}
                  <div className="absolute inset-0 bg-pharmacy-600 bg-opacity-0 group-hover:bg-opacity-5 transition duration-200 pointer-events-none"></div>
                </div>
              ))}
           </div>
        </div>
      </div>

      {/* 3. RIGHT SIDEBAR: CART (Fixed Width) */}
      <div className="w-[420px] bg-white border-l border-gray-200 shadow-2xl flex flex-col h-full z-30">

          {/* Cart Header */}
          <div className="p-4 bg-gray-800 text-white flex justify-between items-center shadow-md">
             <div className="flex items-center gap-2">
                <ShoppingCart size={20} />
                <span className="font-bold text-lg">{isPreparer && !isCashier ? 'Préparation' : 'Panier'}</span>
                <span className="bg-gray-600 px-2 py-0.5 rounded-full text-xs">{cart.length}</span>
             </div>
             {cart.length > 0 && (
                 <button onClick={clearCart} className="text-gray-400 hover:text-white transition" title="Vider le panier">
                     <Trash size={18} />
                 </button>
             )}
          </div>

          {/* Cart Items List */}
          <div className="flex-1 overflow-y-auto p-2 space-y-2 bg-gray-50">
             {cart.length === 0 ? (
               <div className="h-full flex flex-col items-center justify-center text-gray-400 space-y-4 opacity-50">
                 <ShoppingCart size={64} strokeWidth={1} />
                 <p className="font-medium">Scanner ou cliquer pour ajouter</p>
               </div>
             ) : (
               cart.map(item => (
                 <div key={item.id} className="bg-white p-3 rounded-lg border border-gray-200 shadow-sm flex flex-col gap-2">
                    <div className="flex justify-between items-start">
                        <span className="font-bold text-gray-800 max-w-[150px] truncate">{item.name}</span>
                        <div className="flex items-center gap-2">
                            <span className="font-bold text-gray-900">{formatCurrency(item.price * item.quantity)}</span>
                            <button onClick={() => removeFromCart(item.id)} className="text-gray-400 hover:text-red-500 transition p-0.5 rounded-md hover:bg-red-50" title="Retirer l'article">
                                <X size={16} />
                            </button>
                        </div>
                    </div>
                    <div className="flex justify-between items-center">
                        <span className="text-xs text-gray-400">{item.dosage}</span>
                        <div className="flex items-center bg-gray-100 rounded-lg p-1">
                            <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:bg-white rounded shadow-sm transition"><Minus size={14}/></button>
                            <span className="w-8 text-center font-bold text-sm">{item.quantity}</span>
                            <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:bg-white rounded shadow-sm transition"><Plus size={14}/></button>
                        </div>
                    </div>
                 </div>
               ))
             )}
          </div>

          {/* Cart Actions & Footer */}
          <div className="bg-white border-t border-gray-200 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]">

             {/* AI Check Button (Compact) */}
             {cart.length >= 2 && (
               <div className="px-4 py-2 bg-indigo-50 border-b border-indigo-100 flex justify-between items-center">
                  <span className="text-xs text-indigo-700 font-medium">Sécurité Médicament</span>
                  <button 
                    onClick={checkInteractions}
                    disabled={isChecking}
                    className="text-xs bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full hover:bg-indigo-200 transition flex items-center gap-1"
                  >
                    {isChecking ? <Loader2 size={12} className="animate-spin"/> : <AlertOctagon size={12}/>} Vérifier (IA)
                  </button>
               </div>
             )}
             {interactionAlert && (
                 <div className="px-4 py-2 bg-yellow-50 text-xs text-yellow-800 border-b border-yellow-200 max-h-24 overflow-y-auto">
                     {interactionAlert}
                 </div>
             )}

             {/* Main Checkout Area */}
             <div className="p-4 space-y-4">

                 {/* 1. Subtotals & Insurance Toggle */}
                 <div className="space-y-2">
                     <div className="flex justify-between text-gray-500 text-sm">
                         <span>Sous-total</span>
                         <span>{formatCurrency(totalAmount)}</span>
                     </div>

                     <div className="flex items-center justify-between">
                         <button 
                            onClick={() => setShowInsurance(!showInsurance)}
                            className={`text-xs flex items-center gap-1 font-bold ${showInsurance ? 'text-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}
                         >
                            <ShieldCheck size={14} /> {selectedInsuranceId ? 'Assurance Active' : 'Ajouter Assurance'} {showInsurance ? <ChevronUp size={12}/> : <ChevronDown size={12}/>}
                         </button>
                         {selectedInsuranceId && (
                             <span className="text-sm text-indigo-600 font-medium">-{formatCurrency(insuranceAmount)}</span>
                         )}
                     </div>

                     {/* Collapsible Insurance Form */}
                     {showInsurance && (
                         <div className="bg-indigo-50 p-3 rounded-lg border border-indigo-100 text-sm space-y-2 animate-fade-in">
                             <select 
                                value={selectedInsuranceId} 
                                onChange={(e) => handleInsuranceChange(e.target.value)}
                                className="w-full p-2 border border-indigo-200 rounded bg-white outline-none focus:ring-1 focus:ring-indigo-500"
                             >
                                <option value="">Choisir Organisme...</option>
                                {insurances.map(ins => <option key={ins.id} value={ins.id}>{ins.name}</option>)}
                             </select>
                             {selectedInsuranceId && (
                                 <>
                                    <div className="flex items-center gap-2">
                                        <span className="text-gray-500 text-xs w-16">Taux %</span>
                                        <input type="number" value={coverageRate} onChange={e => setCoverageRate(Number(e.target.value))} className="w-16 p-1 border rounded text-right"/>
                                    </div>
                                    <input type="text" placeholder="Nom Patient" value={patientName} onChange={e => setPatientName(e.target.value)} className="w-full p-1.5 border rounded"/>
                                    <input type="text" placeholder="Matricule" value={policyNumber} onChange={e => setPolicyNumber(e.target.value)} className="w-full p-1.5 border rounded"/>
                                 </>
                             )}
                         </div>
                     )}

                     <div className="flex justify-between items-end border-t border-gray-100 pt-2">
                         <span className="font-bold text-gray-800 text-lg">À Payer</span>
                         <span className="font-bold text-pharmacy-700 text-3xl">{formatCurrency(patientAmount)}</span>
                     </div>
                 </div>

                 {/* 2. Payment Method Selector (Only for Cashier) */}
                 {!isPreparer || isCashier ? (
                    <div className="space-y-3">
                        <div className="grid grid-cols-3 gap-2">
                           <button 
                             onClick={() => setPaymentMethod('CASH')}
                             className={`py-2 rounded-lg flex flex-col items-center justify-center border-2 transition ${paymentMethod === 'CASH' ? 'border-green-500 bg-green-50 text-green-700' : 'border-transparent bg-gray-100 text-gray-500 hover:bg-gray-200'}`}
                           >
                               <Banknote size={20} />
                               <span className="text-[10px] font-bold uppercase mt-1">Espèces</span>
                           </button>
                           <button 
                             onClick={() => setPaymentMethod('MOBILE_MONEY')}
                             className={`py-2 rounded-lg flex flex-col items-center justify-center border-2 transition ${paymentMethod === 'MOBILE_MONEY' ? 'border-orange-500 bg-orange-50 text-orange-700' : 'border-transparent bg-gray-100 text-gray-500 hover:bg-gray-200'}`}
                           >
                               <Smartphone size={20} />
                               <span className="text-[10px] font-bold uppercase mt-1">Mobile</span>
                           </button>
                           <button 
                             onClick={() => setPaymentMethod('CARD')}
                             className={`py-2 rounded-lg flex flex-col items-center justify-center border-2 transition ${paymentMethod === 'CARD' ? 'border-purple-500 bg-purple-50 text-purple-700' : 'border-transparent bg-gray-100 text-gray-500 hover:bg-gray-200'}`}
                           >
                               <CreditCard size={20} />
                               <span className="text-[10px] font-bold uppercase mt-1">Carte</span>
                           </button>
                        </div>

                        {/* Cash Input */}
                        {paymentMethod === 'CASH' && (
                            <div className="bg-green-50 p-3 rounded-xl border border-green-200">
                                <div className="flex justify-between items-center mb-1">
                                    <label className="text-xs font-bold text-green-800 uppercase">Reçu du client</label>
                                    {typeof amountReceived === 'number' && (
                                        <div className={`text-sm font-bold flex items-center gap-1 ${changeDue < 0 ? 'text-red-500' : 'text-green-700'}`}>
                                            <Coins size={14} /> Rendre: {changeDue < 0 ? '...' : formatCurrency(changeDue)}
                                        </div>
                                    )}
                                </div>
                                <input 
                                  ref={cashInputRef}
                                  type="number" 
                                  placeholder="Entrer montant..." 
                                  value={amountReceived}
                                  onChange={(e) => setAmountReceived(e.target.value === '' ? '' : parseFloat(e.target.value))}
                                  className="w-full bg-white border border-green-300 rounded-lg p-2 text-xl font-bold text-gray-900 focus:ring-2 focus:ring-green-500 outline-none"
                                />
                            </div>
                        )}

                        <button 
                            onClick={handleCheckout}
                            disabled={cart.length === 0 || !isAmountSufficient}
                            className={`w-full py-4 rounded-xl font-bold text-xl shadow-lg transition transform active:scale-95 flex items-center justify-center gap-2 ${
                            cart.length === 0 || !isAmountSufficient
                            ? 'bg-gray-300 text-gray-500 cursor-not-allowed' 
                            : 'bg-pharmacy-600 text-white hover:bg-pharmacy-700'
                            }`}
                        >
                            <CheckCircle size={24} />
                            {paymentMethod === 'CASH' && !isAmountSufficient ? 'Montant Insuffisant' : 'ENCAISSER'}
                        </button>
                    </div>
                 ) : (
                     // Agent / Seller Mode Button
                     <div className="flex gap-2">
                        <button 
                            onClick={clearCart}
                            disabled={cart.length === 0}
                            className={`flex-1 py-4 rounded-xl font-bold text-lg shadow-md transition flex items-center justify-center gap-2 ${
                            cart.length === 0 
                            ? 'bg-gray-100 text-gray-400 cursor-not-allowed' 
                            : 'bg-red-50 text-red-600 hover:bg-red-100 border border-red-200'
                            }`}
                        >
                            <Trash size={20} /> Annuler
                        </button>
                        <button 
                            onClick={handleSendToCashier}
                            disabled={cart.length === 0}
                            className={`flex-[2] py-4 rounded-xl font-bold text-lg shadow-lg transition transform active:scale-95 flex items-center justify-center gap-2 ${
                            cart.length === 0 
                            ? 'bg-gray-300 text-gray-500 cursor-not-allowed' 
                            : 'bg-blue-600 text-white hover:bg-blue-700'
                            }`}
                        >
                            <Send size={24} /> Envoyer
                        </button>
                    </div>
                 )}
             </div>
          </div>
      </div>
    </div>
  );
};

export default POS;
